const STORY_TUTORIAL_MAP_SIZE = 10;

function createStoryAkari() {
  const base = EMPLOYEE_POOL.find((employee) => employee.id === 122);

  if (!base) {
    throw new Error("七瀬灯里(id:122)が見つかりません");
  }

  return {
    ...structuredClone(base),
    officeId: "hq",
  };
}

