function createStoryTutorialMap() {
  const size = STORY_TUTORIAL_MAP_SIZE;
  const stationX = 5;
  const stationY = 8;
  const stationPositions = [{ x: stationX, y: stationY }];
  const schoolX = 8;
  const schoolY = 1;
  const schoolPositions = [{ x: schoolX, y: schoolY }];
  const factoryX = 8;
  const factoryY = 7;
  const tiles = [];

  for (let y = 0; y < size; y++) {
    for (let x = 0; x < size; x++) {
      const rail = y === 8;
      let feature = FEATURE.NONE;
      let owner = OWNER.OTHER;
      let building = null;
      let rooms = [];
      let age = 0;
      let condition = 100;
      let tutorialTag = null;
      let landPrice = 80 + x * 8 + y * 5;

      if (rail) {
        owner = OWNER.PUBLIC;
      }

      if (x === stationX && y === stationY) {
        feature = FEATURE.STATION;
        owner = OWNER.PUBLIC;
        landPrice += 120;
      } else if ((x === 2 && y >= 1 && y <= 7) || (y === 5 && x >= 1 && x <= 8)) {
        feature = FEATURE.ROAD;
        owner = OWNER.PUBLIC;
        landPrice += 40;
      }

      if (x === 1 && y === 1) {
        feature = FEATURE.HQ;
        owner = OWNER.PLAYER;
        landPrice = 120;
      }

      if (x === 4 && y === 3) {
        owner = OWNER.SALE;
        building = "house_2f";
        rooms = createRooms("house_2f", 0, 0);
        age = 38;
        condition = 10;
        tutorialTag = "old_house";
        landPrice = 180;
      }

      if (x === 6 && y === 3) {
        owner = OWNER.SALE;
        building = null;
        tutorialTag = "apartment_land";
        landPrice = 150;
      }

      if (x === 7 && y === 2) {
        owner = OWNER.OTHER;
        building = "house_1f";
        rooms = createRooms("house_1f", 90, 0);
        age = 12;
        condition = 72;
        landPrice = 160;
      }

      if (x === 3 && y === 6) {
        owner = OWNER.OTHER;
        building = "convenience";
        rooms = createRooms("convenience", 100, 0);
        age = 5;
        condition = 86;
        landPrice = 220;
      }

      if (x === 8 && y === 6) {
        owner = OWNER.OTHER;
        building = "small_factory";
        rooms = createRooms("small_factory", 100, 0);
        age = 18;
        condition = 68;
        landPrice = 210;
      }

      if (feature !== FEATURE.NONE && feature !== FEATURE.HQ) {
        building = null;
        rooms = [];
        age = 0;
        condition = 100;
        tutorialTag = null;
      }

      tiles.push({
        id: y * size + x,
        x,
        y,
        terrain: TERRAIN.PLAIN,
        feature,
        rail,
        zone: y >= 7 ? ZONE.INDUSTRIAL : x >= 6 ? ZONE.COMMERCIAL : ZONE.RESIDENTIAL,
        owner,
        building,
        buildingMainId: null,
        rooms,
        age,
        condition,
        vacancyMonths: 0,
        recoveryMode: false,
        landPrice,
        tutorialTag,
      });
    }
  }

  return {
    tiles: recalculateTileZonesByFacilities(tiles),
    stationX,
    stationY,
    stationPositions,
    schoolX,
    schoolY,
    schoolPositions,
    factoryX,
    factoryY,
    tutorialOldHouseId: 3 * size + 4,
    tutorialApartmentLandId: 3 * size + 6,
  };
}


function createGifuStoryMap() {
  const size = 15;
  const stationX = 7;
  const stationY = 5;
  const hqX = 8;
  const hqY = 10;
  const stationPositions = [{ x: stationX, y: stationY, name: "岐阜駅" }];
  const schoolX = 3;
  const schoolY = 3;
  const schoolPositions = [{ x: schoolX, y: schoolY }];
  const roadSet = new Set();
  const railSet = new Set();
  const tiles = [];

  function addRail(x, y) {
    if (x >= 0 && x < size && y >= 0 && y < size) railSet.add(`${x},${y}`);
  }

  function addRailLPath(points) {
    for (let i = 0; i < points.length - 1; i++) {
      const [x1, y1] = points[i];
      const [x2, y2] = points[i + 1];
      const stepX = x2 >= x1 ? 1 : -1;
      const stepY = y2 >= y1 ? 1 : -1;
      for (let x = x1; x !== x2; x += stepX) addRail(x, y1);
      addRail(x2, y1);
      for (let y = y1; y !== y2; y += stepY) addRail(x2, y);
      addRail(x2, y2);
    }
  }

  function addRoad(x, y) {
    if (x >= 0 && x < size && y >= 0 && y < size) roadSet.add(`${x},${y}`);
  }

  function addRoadLPath(points) {
    for (let i = 0; i < points.length - 1; i++) {
      const [x1, y1] = points[i];
      const [x2, y2] = points[i + 1];
      const stepX = x2 >= x1 ? 1 : -1;
      const stepY = y2 >= y1 ? 1 : -1;
      for (let x = x1; x !== x2; x += stepX) addRoad(x, y1);
      addRoad(x2, y1);
      for (let y = y1; y !== y2; y += stepY) addRoad(x2, y);
      addRoad(x2, y2);
    }
  }

  for (let x = 0; x <= stationX; x++) addRail(x, stationY);
  addRailLPath([
    [7, 5], [7, 6], [8, 7], [8, 9], [9, 11], [10, 13], [11, 14],
  ]);

  for (let x = 1; x <= 13; x++) roadSet.add(`${x},4`);
  for (let y = 1; y <= 13; y++) roadSet.add(`6,${y}`);
  for (let x = 1; x <= 13; x++) {
    if (x !== hqX) roadSet.add(`${x},9`);
  }
  for (let y = 1; y <= 13; y++) roadSet.add(`12,${y}`);

  const fixedBuildings = {
    "1,1": { owner: OWNER.OTHER, building: null, landPrice: 150 },
    "4,2": { owner: OWNER.OTHER, building: "house_1f", rent: 70, age: 8, condition: 78, landPrice: 165 },
    "9,2": { owner: OWNER.SALE, building: null, landPrice: 175 },
    "13,2": { owner: OWNER.OTHER, building: "house_2f", rent: 75, age: 18, condition: 70, landPrice: 185 },
    "2,6": { owner: OWNER.SALE, building: null, landPrice: 170 },
    "5,6": { owner: OWNER.OTHER, building: "convenience", rent: 82, age: 6, condition: 84, landPrice: 225 },
    "11,6": { owner: OWNER.OTHER, building: null, landPrice: 190 },
    "2,8": { owner: OWNER.OTHER, building: "house_1f", rent: 72, age: 11, condition: 76, landPrice: 165 },
    "4,10": { owner: OWNER.SALE, building: null, landPrice: 155 },
    "7,10": { owner: OWNER.OTHER, building: "house_1f", rent: 70, age: 12, condition: 72, landPrice: 170 },
    "11,10": { owner: OWNER.OTHER, building: null, landPrice: 180 },
    "2,13": { owner: OWNER.OTHER, building: null, landPrice: 145 },
    "5,13": { owner: OWNER.OTHER, building: "house_2f", rent: 72, age: 22, condition: 67, landPrice: 165 },
    "13,13": { owner: OWNER.SALE, building: null, landPrice: 160 },
  };

  function getGifuZone(x, y) {
    if (getDistance(x, y, stationX, stationY) <= 2) return ZONE.COMMERCIAL;
    return ZONE.GENERAL;
  }

  for (let y = 0; y < size; y++) {
    for (let x = 0; x < size; x++) {
      const key = `${x},${y}`;
      const rail = railSet.has(key);
      const fixed = fixedBuildings[key];
      let feature = FEATURE.NONE;
      let owner = OWNER.OTHER;
      let building = null;
      let rooms = [];
      let age = 0;
      let condition = 100;
      let landPrice = 130 + Math.max(0, 12 - getDistance(x, y, stationX, stationY)) * 10;
      let zone = getGifuZone(x, y);
      let officeId = null;
      let officeName = null;
      let officeRange = null;
      let hqType = null;
      let hqName = null;
      let hqCost = null;

      if (fixed) {
        owner = fixed.owner;
        building = fixed.building;
        age = fixed.age ?? 0;
        condition = fixed.condition ?? 100;
        landPrice = fixed.landPrice ?? landPrice;
        rooms = building ? createRooms(building, fixed.rent ?? 72, 0) : [];
      }

      if (roadSet.has(key)) {
        feature = FEATURE.ROAD;
        owner = OWNER.PUBLIC;
        building = null;
        rooms = [];
        age = 0;
        condition = 100;
        landPrice += 30;
      }

      if (rail) {
        feature = FEATURE.NONE;
        owner = OWNER.PUBLIC;
        building = null;
        rooms = [];
        age = 0;
        condition = 100;
      }

      if (x === stationX && y === stationY) {
        feature = FEATURE.STATION;
        owner = OWNER.PUBLIC;
        building = null;
        rooms = [];
        age = 0;
        condition = 100;
        landPrice += 220;
        zone = ZONE.COMMERCIAL;
      }

      if (schoolPositions.some((school) => school.x === x && school.y === y)) {
        feature = FEATURE.SCHOOL;
        owner = OWNER.PUBLIC;
        building = null;
        rooms = [];
        age = 0;
        condition = 100;
        landPrice += 80;
        zone = ZONE.GENERAL;
      }

      if (x === hqX && y === hqY) {
        feature = FEATURE.HQ;
        owner = OWNER.PLAYER;
        building = null;
        rooms = [];
        age = 0;
        condition = 100;
        landPrice = 220;
        zone = ZONE.GENERAL;
        officeId = "hq";
        officeName = "本社";
        officeRange = HQ_ACTION_RANGE;
        hqType = "normal";
        hqName = "本社";
        hqCost = 0;
      }

      if (
        owner === OWNER.OTHER &&
        !building &&
        feature === FEATURE.NONE &&
        !rail &&
        ((x * 17 + y * 31) % 5 === 0)
      ) {
        owner = OWNER.SALE;
      }

      tiles.push({
        id: y * size + x,
        x,
        y,
        terrain: TERRAIN.PLAIN,
        feature,
        rail,
        zone,
        owner,
        building,
        buildingMainId: null,
        rooms,
        age,
        condition,
        vacancyMonths: 0,
        recoveryMode: false,
        landPrice: Math.max(80, landPrice),
        officeId,
        officeName,
        officeRange,
        hqType,
        hqName,
        hqCost,
      });
    }
  }

  placeStoryRivalOffice(tiles, "A", "岐阜まちづくり不動産", [
    { x: 12, y: 12 },
    { x: 2, y: 12 },
  ]);

  return {
    tiles: recalculateTileZonesByFacilities(tiles),
    stationX,
    stationY,
    stationPositions,
    schoolX,
    schoolY,
    schoolPositions,
    factoryX: null,
    factoryY: null,
    factoryPositions: [],
  };
}


function createNagoyaStoryMap(gifuSourceTiles = []) {
  const size = 30;
  const gifuStationX = 7;
  const gifuStationY = 5;
  const nagoyaStationX = 12;
  const nagoyaStationY = 20;
  const stationX = nagoyaStationX;
  const stationY = nagoyaStationY;
  const stationPositions = [
    { x: gifuStationX, y: gifuStationY, name: "岐阜駅" },
    { x: nagoyaStationX, y: nagoyaStationY, name: "名古屋駅" },
  ];
  const schoolPositions = [
    { x: 3, y: 3, name: "岐阜の学校" },
    { x: 22, y: 16, name: "名古屋北部の学校" },
    { x: 25, y: 23, name: "名古屋南部の学校" },
  ];
  const schoolX = schoolPositions[0].x;
  const schoolY = schoolPositions[0].y;
  const factoryX = 22;
  const factoryY = 27;
  const factoryYard = [];
  const branchTutorialX = 11;
  const branchTutorialY = 17;

  const fixedGifuMap = createGifuStoryMap();
  const sourceMap = new Map();
  const gifuTilesToUse = Array.isArray(gifuSourceTiles) && gifuSourceTiles.length > 0
    ? gifuSourceTiles
    : fixedGifuMap.tiles;

  gifuTilesToUse.forEach((tile) => {
    if ((tile.x ?? 0) >= 0 && (tile.x ?? 0) < 15 && (tile.y ?? 0) >= 0 && (tile.y ?? 0) < 15) {
      sourceMap.set(`${tile.x},${tile.y}`, tile);
    }
  });

  const fixedGifuMapByKey = new Map(fixedGifuMap.tiles.map((tile) => [`${tile.x},${tile.y}`, tile]));
  const railSet = new Set();
  const roadSet = new Set();
  const tiles = [];

  function addRail(x, y) {
    if (x >= 0 && x < size && y >= 0 && y < size) railSet.add(`${x},${y}`);
  }

  function addRailLPath(points) {
    for (let i = 0; i < points.length - 1; i++) {
      const [x1, y1] = points[i];
      const [x2, y2] = points[i + 1];
      const stepX = x2 >= x1 ? 1 : -1;
      const stepY = y2 >= y1 ? 1 : -1;
      for (let x = x1; x !== x2; x += stepX) addRail(x, y1);
      addRail(x2, y1);
      for (let y = y1; y !== y2; y += stepY) addRail(x2, y);
      addRail(x2, y2);
    }
  }

  function addRoad(x, y) {
    if (x >= 0 && x < size && y >= 0 && y < size) roadSet.add(`${x},${y}`);
  }

  function addRoadLPath(points) {
    for (let i = 0; i < points.length - 1; i++) {
      const [x1, y1] = points[i];
      const [x2, y2] = points[i + 1];
      const stepX = x2 >= x1 ? 1 : -1;
      const stepY = y2 >= y1 ? 1 : -1;
      for (let x = x1; x !== x2; x += stepX) addRoad(x, y1);
      addRoad(x2, y1);
      for (let y = y1; y !== y2; y += stepY) addRoad(x2, y);
      addRoad(x2, y2);
    }
  }

  for (let x = 0; x <= gifuStationX; x++) addRail(x, gifuStationY);
  addRailLPath([
    [7, 5], [7, 6], [8, 7], [8, 9], [9, 11],
    [10, 13], [11, 16], [12, 20],
  ]);
  for (let x = 0; x < size; x++) addRail(x, nagoyaStationY);
  addRailLPath([
    [12, 20], [13, 21], [14, 22], [15, 23], [16, 24],
    [17, 25], [18, 27], [19, 29],
  ]);

  for (let x = 1; x <= 13; x++) roadSet.add(`${x},4`);
  for (let y = 1; y <= 13; y++) roadSet.add(`6,${y}`);
  for (let x = 1; x <= 13; x++) if (x !== 9) roadSet.add(`${x},9`);
  for (let y = 1; y <= 13; y++) roadSet.add(`12,${y}`);
  for (let y = 15; y <= 28; y++) roadSet.add(`8,${y}`);
  for (let y = 15; y <= 28; y++) roadSet.add(`16,${y}`);
  for (let y = 18; y <= 29; y++) roadSet.add(`23,${y}`);
  for (let x = 6; x <= 24; x++) roadSet.add(`${x},18`);
  for (let x = 6; x <= 24; x++) roadSet.add(`${x},22`);
  for (let x = 10; x <= 27; x++) roadSet.add(`${x},27`);
  for (let y = 9; y <= 29; y++) roadSet.add(`10,${y}`);
  for (let y = 9; y <= 29; y++) roadSet.add(`14,${y}`);
  for (let x = 6; x <= 18; x++) roadSet.add(`${x},16`);

  // 岐阜本社から支店予定地、名古屋市街へつながる幹線道路。
  // チュートリアルでは道路が途切れて見えないよう、L字で連続させる。
  addRoadLPath([
    [8, 10], [8, 14], [11, 14], [11, 17], [12, 17], [12, 20], [24, 20]
  ]);
  for (let x = 0; x < size; x++) addRoad(x, 20);

  const fixedNagoyaBuildings = {
    "8,17": { owner: OWNER.OTHER, building: "drugstore", rent: 90, age: 7, condition: 88 },
    "16,18": { owner: OWNER.OTHER, building: "supermarket", rent: 88, age: 9, condition: 88 },
    "20,21": { owner: OWNER.OTHER, building: "convenience", rent: 86, age: 6, condition: 90 },
    "18,23": { owner: OWNER.SALE, building: "drugstore", rent: 82, age: 12, condition: 78 },
    "7,25": { owner: OWNER.OTHER, building: "house_2f", rent: 76, age: 12, condition: 82 },
    "22,25": { owner: OWNER.OTHER, building: "warehouse", rent: 82, age: 9, condition: 84 },
  };

  const multiNagoyaBuildings = [
    { x: 7, y: 21, owner: OWNER.OTHER, building: "mansion_5f", rent: 82, age: 10, condition: 86 },
    { x: 10, y: 22, owner: OWNER.OTHER, building: "commercial_big", rent: 88, age: 8, condition: 90 },
    { x: 14, y: 21, owner: OWNER.OTHER, building: "mansion_7f", rent: 84, age: 9, condition: 88 },
    { x: 18, y: 21, owner: OWNER.SALE, building: "mansion_5f", rent: 78, age: 16, condition: 76 },
    { x: 22, y: 27, owner: OWNER.OTHER, building: "large_factory", rent: 78, age: 18, condition: 74 },
  ];

  function getBaseZone(x, y) {
    if (y >= 26 && x >= 18) return ZONE.INDUSTRIAL;
    if (getDistance(x, y, nagoyaStationX, nagoyaStationY) <= 3) return ZONE.COMMERCIAL;
    if (getDistance(x, y, gifuStationX, gifuStationY) <= 2) return ZONE.COMMERCIAL;
    return ZONE.GENERAL;
  }

  function getBaseLandPrice(x, y) {
    if (x < 15 && y < 15) return 130 + Math.max(0, 12 - getDistance(x, y, gifuStationX, gifuStationY)) * 10;
    const nagoyaDistance = getDistance(x, y, nagoyaStationX, nagoyaStationY);
    const railDistance = Math.min(
      Math.abs(x - 11),
      Math.abs(y - nagoyaStationY),
      Math.abs(x - nagoyaStationX)
    );
    return 180 + Math.max(0, 20 - nagoyaDistance) * 32 + Math.max(0, 6 - railDistance) * 18;
  }

  for (let y = 0; y < size; y++) {
    for (let x = 0; x < size; x++) {
      const key = `${x},${y}`;
      const fromGifu = x < 15 && y < 15 ? (sourceMap.get(key) ?? fixedGifuMapByKey.get(key)) : null;
      const rail = railSet.has(key);
      const fixedNagoya = fixedNagoyaBuildings[key];
      let feature = FEATURE.NONE;
      let owner = OWNER.SALE;
      let building = null;
      let rooms = [];
      let age = 0;
      let condition = 100;
      let landPrice = getBaseLandPrice(x, y);
      let zone = getBaseZone(x, y);
      let buildingMainId = null;
      let vacancyMonths = 0;
      let recoveryMode = false;
      let officeId = null;
      let officeName = null;
      let officeRange = null;
      let hqType = null;
      let hqName = null;
      let hqCost = null;
      let tutorialTag = null;

      if (fromGifu) {
        feature = fromGifu.feature ?? FEATURE.NONE;
        owner = fromGifu.owner ?? OWNER.SALE;
        building = fromGifu.building ?? null;
        rooms = Array.isArray(fromGifu.rooms) ? structuredClone(fromGifu.rooms) : [];
        age = fromGifu.age ?? 0;
        condition = fromGifu.condition ?? 100;
        landPrice = fromGifu.landPrice ?? landPrice;
        buildingMainId = fromGifu.buildingMainId ?? null;
        vacancyMonths = fromGifu.vacancyMonths ?? 0;
        recoveryMode = fromGifu.recoveryMode ?? false;
        officeId = fromGifu.officeId ?? null;
        officeName = fromGifu.officeName ?? null;
        officeRange = fromGifu.officeRange ?? null;
        hqType = fromGifu.hqType ?? null;
        hqName = fromGifu.hqName ?? null;
        hqCost = fromGifu.hqCost ?? null;
        zone = getBaseZone(x, y);
      } else {
        if (roadSet.has(key)) {
          feature = FEATURE.ROAD;
          owner = OWNER.PUBLIC;
          landPrice += 30;
        }

        if (fixedNagoya && !rail) {
          owner = fixedNagoya.owner;
          building = fixedNagoya.building;
          age = fixedNagoya.age ?? 0;
          condition = fixedNagoya.condition ?? 100;
          rooms = building ? createRooms(building, fixedNagoya.rent ?? 82, 0) : [];
          landPrice += building && (building.includes("mansion") || building === "commercial_big") ? 420 : 260;
        } else if (!rail && owner !== OWNER.PUBLIC) {
          const corridor = y >= 10 && y <= 20 && x >= 4 && x <= 14;
          if (corridor && ((x + y) % 5 === 0)) {
            owner = OWNER.OTHER;
            building = (x + y) % 10 === 0 ? "convenience" : "house_2f";
            rooms = createRooms(building, 76, 0);
            age = 10 + ((x + y) % 8);
            condition = 72 + ((x + y) % 18);
            landPrice += 120;
          } else {
            owner = ((x * 7 + y * 11) % 10) < 2 ? OWNER.SALE : OWNER.OTHER;
          }
        }
      }

      if (rail) {
        feature = FEATURE.NONE;
        owner = OWNER.PUBLIC;
        building = null;
        buildingMainId = null;
        rooms = [];
        age = 0;
        condition = 100;
      }

      if ((x === gifuStationX && y === gifuStationY) || (x === nagoyaStationX && y === nagoyaStationY)) {
        feature = FEATURE.STATION;
        owner = OWNER.PUBLIC;
        building = null;
        buildingMainId = null;
        rooms = [];
        age = 0;
        condition = 100;
        landPrice += x === nagoyaStationX && y === nagoyaStationY ? 520 : 220;
        zone = ZONE.COMMERCIAL;
      }

      if (schoolPositions.some((school) => school.x === x && school.y === y)) {
        feature = FEATURE.SCHOOL;
        owner = OWNER.PUBLIC;
        building = null;
        buildingMainId = null;
        rooms = [];
        landPrice += 80;
        zone = ZONE.GENERAL;
      }

      if (false && x === factoryX && y === factoryY) {
        feature = FEATURE.FACTORY;
        owner = OWNER.PUBLIC;
        building = null;
        buildingMainId = null;
        rooms = [];
        landPrice += 120;
        zone = ZONE.INDUSTRIAL;
      }

      if (x === 8 && y === 10) {
        feature = FEATURE.HQ;
        owner = OWNER.PLAYER;
        building = null;
        buildingMainId = null;
        rooms = [];
        age = 0;
        condition = 100;
        landPrice = 220;
        zone = ZONE.GENERAL;
        officeId = "hq";
        officeName = "本社";
        officeRange = HQ_ACTION_RANGE;
        hqType = "normal";
        hqName = "本社";
        hqCost = 0;
      }

      if (x === branchTutorialX && y === branchTutorialY) {
        feature = FEATURE.NONE;
        owner = OWNER.PLAYER;
        building = null;
        buildingMainId = null;
        rooms = [];
        age = 0;
        condition = 100;
        tutorialTag = "nagoya_branch_land";
        landPrice = 520;
        zone = ZONE.GENERAL;
      }

      tiles.push({
        id: y * size + x,
        x,
        y,
        terrain: TERRAIN.PLAIN,
        feature,
        rail,
        zone,
        owner,
        building,
        buildingMainId,
        rooms,
        age,
        condition,
        vacancyMonths,
        recoveryMode,
        landPrice: Math.max(80, landPrice),
        officeId,
        officeName,
        officeRange,
        hqType,
        hqName,
        hqCost,
        tutorialTag,
      });
    }
  }

  function placeCompletedBuilding(startX, startY, buildingKey, owner, rent, ageValue, conditionValue) {
    const buildingInfo = BUILDINGS[buildingKey];
    if (!buildingInfo) return;
    const mainTile = tiles.find((tile) => tile.x === startX && tile.y === startY);
    if (!mainTile) return;
    const mainId = mainTile.id;

    for (let dy = 0; dy < buildingInfo.height; dy++) {
      for (let dx = 0; dx < buildingInfo.width; dx++) {
        const tile = tiles.find((target) => target.x === startX + dx && target.y === startY + dy);
        if (!tile) continue;
        if (tile.feature === FEATURE.STATION || tile.feature === FEATURE.SCHOOL || tile.rail) continue;
        tile.feature = FEATURE.NONE;
        tile.owner = owner;
        tile.building = buildingKey;
        tile.buildingMainId = dx === 0 && dy === 0 ? null : mainId;
        tile.rooms = dx === 0 && dy === 0 ? createRooms(buildingKey, rent, 0) : [];
        tile.age = ageValue;
        tile.condition = conditionValue;
        tile.vacancyMonths = 0;
        tile.recoveryMode = false;
        tile.zone = buildingInfo.category === "工業" ? ZONE.INDUSTRIAL : getBaseZone(tile.x, tile.y);
        tile.landPrice = Math.max(tile.landPrice, getBaseLandPrice(tile.x, tile.y) + 300);
      }
    }
  }

  multiNagoyaBuildings.forEach((entry) => {
    placeCompletedBuilding(entry.x, entry.y, entry.building, entry.owner, entry.rent, entry.age, entry.condition);
  });

  placeStoryRivalOffice(tiles, "B", "中京圏開発", [
    { x: 23, y: 22 },
    { x: 19, y: 17 },
    { x: 25, y: 12 },
  ]);

  return {
    tiles: recalculateTileZonesByFacilities(tiles),
    stationX,
    stationY,
    stationPositions,
    schoolX,
    schoolY,
    schoolPositions,
    factoryX,
    factoryY,
    factoryPositions: factoryYard,
    tutorialBranchLandId: branchTutorialY * size + branchTutorialX,
  };
}

function getSaveSlotKey(slot) {
  return `realEstateGameSave_slot${slot}`;
}

function getCurrentSaveSlot() {
  if (typeof window === "undefined") return DEFAULT_SAVE_SLOT;
  const rawSlot = Number(window.localStorage.getItem("realEstateGameCurrentSlot") ?? DEFAULT_SAVE_SLOT);
  if (!Number.isFinite(rawSlot)) return DEFAULT_SAVE_SLOT;
  return Math.min(SAVE_SLOT_COUNT, Math.max(1, Math.round(rawSlot)));
}

function readSaveSlot(slot) {
  if (typeof window === "undefined") return null;

  try {
    const rawSaveData = window.localStorage.getItem(getSaveSlotKey(slot));
    if (!rawSaveData) return null;
    const parsedSaveData = JSON.parse(rawSaveData);
    if (!parsedSaveData || typeof parsedSaveData !== "object") return null;
    if (!Array.isArray(parsedSaveData.tiles)) return null;
    return parsedSaveData;
  } catch (error) {
    console.warn(`Save slot ${slot} could not be loaded.`, error);
    return null;
  }
}

function getDefaultAccountData() {
  return {
    playerRank: 1,
    playerExp: 0,
    employeeVault: [],
    unlockedStoryAkari: false,
    hasClearedGifuChapter: false,
    hasClearedNagoyaChapter: false,
    hasClearedKyotoChapter: false,
    hasClearedOsakaChapter: false,
    hasClearedTokyoChapter: false,
    hasCompletedKyotoTourismTutorial: false,
    hasCompletedOsakaIndustrialTutorial: false,
    rookieEmployeeTickets: 0,
    employeeTickets: 0,
    premiumEmployeeTickets: 0,
    medals: 0,
    shine: 0,
    releaseCampaignClaimed: false,
    silverSheets: 0,
    goldSheets: 0,
    rainbowSheets: 0,
    specialMissionData: null,
    items: {},
    usedSecretCommands: {},
    [DEV_DEMO_SHEET_GRANT_KEY]: true,
    updatedAt: "",
  };
}

function normalizeAccountData(rawAccountData) {
  const parsedAccountData = rawAccountData && typeof rawAccountData === "object" ? rawAccountData : {};
  const demoSheetsGranted = parsedAccountData[DEV_DEMO_SHEET_GRANT_KEY] === true;
  const safeMedals = Math.max(0, Math.round(Number(parsedAccountData.medals ?? parsedAccountData.medal ?? 0) || 0));
  const safeShine = Math.max(0, Math.round(Number(parsedAccountData.shine ?? parsedAccountData.shines ?? 0) || 0));
  const safeSilverSheets = 0;
  const safeGoldSheets = 0;
  const safeRainbowSheets = 0;

  return {
    playerRank: Math.max(1, Math.round(Number(parsedAccountData.playerRank) || 1)),
    playerExp: Math.max(0, Math.round(Number(parsedAccountData.playerExp) || 0)),
    employeeVault: Array.isArray(parsedAccountData.employeeVault) ? parsedAccountData.employeeVault : [],
    unlockedStoryAkari: parsedAccountData.unlockedStoryAkari === true,
    hasClearedGifuChapter: parsedAccountData.hasClearedGifuChapter === true,
    hasClearedNagoyaChapter: parsedAccountData.hasClearedNagoyaChapter === true,
    hasClearedKyotoChapter: parsedAccountData.hasClearedKyotoChapter === true,
    hasClearedOsakaChapter: parsedAccountData.hasClearedOsakaChapter === true,
    hasClearedTokyoChapter: parsedAccountData.hasClearedTokyoChapter === true,
    hasCompletedKyotoTourismTutorial: parsedAccountData.hasCompletedKyotoTourismTutorial === true,
    hasCompletedOsakaIndustrialTutorial: parsedAccountData.hasCompletedOsakaIndustrialTutorial === true,
    rookieEmployeeTickets: Math.max(0, Math.round(Number(parsedAccountData.rookieEmployeeTickets) || 0)),
    employeeTickets: Math.max(0, Math.round(Number(parsedAccountData.employeeTickets ?? 0) || 0)),
    premiumEmployeeTickets: Math.max(0, Math.round(Number(parsedAccountData.premiumEmployeeTickets) || 0)),
    medals: safeMedals,
    shine: safeShine,
    releaseCampaignClaimed: parsedAccountData.releaseCampaignClaimed === true,
    silverSheets: safeSilverSheets,
    goldSheets: safeGoldSheets,
    rainbowSheets: safeRainbowSheets,
    specialMissionData: parsedAccountData.specialMissionData && typeof parsedAccountData.specialMissionData === "object" ? parsedAccountData.specialMissionData : null,
    items: parsedAccountData.items && typeof parsedAccountData.items === "object" ? Object.fromEntries(Object.entries(parsedAccountData.items).map(([key, value]) => [key, Math.max(0, Math.round(Number(value) || 0))])) : {},
    usedSecretCommands: parsedAccountData.usedSecretCommands && typeof parsedAccountData.usedSecretCommands === "object" ? parsedAccountData.usedSecretCommands : {},
    [DEV_DEMO_SHEET_GRANT_KEY]: true,
    updatedAt: parsedAccountData.updatedAt ?? "",
  };
}

function readAccountData() {
  if (typeof window === "undefined") {
    return getDefaultAccountData();
  }

  try {
    const rawAccountData = window.localStorage.getItem(ACCOUNT_DATA_KEY);
    if (!rawAccountData) {
      return getDefaultAccountData();
    }

    const parsedAccountData = JSON.parse(rawAccountData);
    if (!parsedAccountData || typeof parsedAccountData !== "object") {
      return getDefaultAccountData();
    }

    return normalizeAccountData(parsedAccountData);
  } catch (error) {
    console.warn("Account data could not be loaded.", error);
    return getDefaultAccountData();
  }
}

function writeAccountData(accountData) {
  if (typeof window === "undefined") return;

  try {
    window.localStorage.setItem(ACCOUNT_DATA_KEY, JSON.stringify(accountData));
  } catch (error) {
    console.warn("Account data could not be saved.", error);
  }
}

function getAccountTicketCounts(accountData = {}, fallbackSaveData = {}) {
  const hasAccountTicketData =
    Object.prototype.hasOwnProperty.call(accountData, "rookieEmployeeTickets") ||
    Object.prototype.hasOwnProperty.call(accountData, "employeeTickets") ||
    Object.prototype.hasOwnProperty.call(accountData, "premiumEmployeeTickets");

  return {
    rookieEmployeeTickets: Math.max(0, Math.round(Number(
      hasAccountTicketData ? accountData.rookieEmployeeTickets : fallbackSaveData.rookieEmployeeTickets
    ) || 0)),
    employeeTickets: Math.max(0, Math.round(Number(
      hasAccountTicketData ? accountData.employeeTickets : (fallbackSaveData.employeeTickets ?? 0)
    ) || 0)),
    premiumEmployeeTickets: Math.max(0, Math.round(Number(
      hasAccountTicketData ? accountData.premiumEmployeeTickets : fallbackSaveData.premiumEmployeeTickets
    ) || 0)),
  };
}

function getEmployeeAbilityTotal(employee) {
  if (!employee) return 0;
  return (Number(employee.leadership) || 0) +
    (Number(employee.sales) || 0) +
    (Number(employee.construction) || 0) +
    (Number(employee.management) || 0);
}

function getComparableEmployeePower(employee) {
  if (!employee) return 0;

  // v199: 社員保管庫は「弱いデータで上書きしない」。
  // レベル → EXP → 覚醒 → 能力合計の順で比較し、セーブスロットをまたいでも強い方を残す。
  const level = Math.max(1, Math.round(Number(employee.level) || 1));
  const exp = Math.max(0, Math.round(Number(employee.exp) || 0));
  const awakening = Math.max(0, Math.round(Number(employee.awakening) || 0));
  const abilityTotal = getEmployeeAbilityTotal(employee);

  return level * 100000000 + exp * 10000 + awakening * 1000 + abilityTotal;
}

function normalizeAccountEmployee(employee) {
  if (!employee || employee.id === 0) return null;

  const level = Math.max(1, Math.round(Number(employee?.level) || 1));
  // normalizeAccountEmployee は EMPLOYEE_AWAKENING_MAX 定義前にも呼ばれるため、TDZ回避で固定値を使う。
  const awakeningMax = 5;
  const assignment = employee.currentAssignment && typeof employee.currentAssignment === "object"
    ? {
        mode: employee.currentAssignment.mode ?? null,
        freeMapKey: employee.currentAssignment.freeMapKey ?? null,
        areaLabel: normalizeAreaDisplayName(employee.currentAssignment.areaLabel ?? ""),
        officeId: employee.currentAssignment.officeId ?? null,
        officeLabel: normalizeOfficeDisplayNameForArea(employee.currentAssignment.officeLabel ?? "", employee.currentAssignment.mode ?? null, employee.currentAssignment.freeMapKey ?? null),
        savedAt: employee.currentAssignment.savedAt ?? "",
      }
    : null;

  return {
    ...employee,
    level,
    exp: Math.max(0, Math.round(Number(employee?.exp) || 0)),
    awakening: Math.max(0, Math.min(awakeningMax, Math.round(Number(employee?.awakening) || 0))),
    baseLeadership: employee.baseLeadership ?? employee.leadership ?? 0,
    baseSales: employee.baseSales ?? employee.sales ?? 0,
    baseConstruction: employee.baseConstruction ?? employee.construction ?? 0,
    baseManagement: employee.baseManagement ?? employee.management ?? 0,
    baseSalary: BASE_EMPLOYEE_SALARY,
    salary: calculateEmployeeSalaryByLevel(level),
    officeId: null,
    // 社員保管庫は会社をまたいで使うため、前の会社での行動中情報は持ち越さない。
    busyUntilMonth: null,
    busyActionName: null,
    founderCarryOver: false,
    currentAssignment: assignment,
    qualifications: normalizeQualificationList(employee.qualifications),
    envelopeId: undefined,
    envelopeType: undefined,
    opened: undefined,
  };
}

function createEmployeeAssignmentFromGame(employee, gameData = {}) {
  const officeId = String(employee?.officeId ?? "");
  if (!employee || !officeId || officeId === "waiting" || officeId === "storage" || officeId === "待機") return null;
  const mode = gameData.currentGameMode ?? gameData.mode ?? null;
  const freeMapKey = gameData.freeMapKey ?? (isFreeModeKey(mode) ? normalizeFreeModeKey(mode) : null);
  const areaLabel = normalizeAreaDisplayName(gameData.areaLabel ?? getGameAreaLabel(mode, freeMapKey));
  return {
    mode,
    freeMapKey,
    areaLabel,
    officeId,
    officeLabel: getAreaOfficeRoleLabel(mode, freeMapKey, officeId),
    saveSlot: gameData.activeSaveSlot ?? null,
    savedAt: new Date().toISOString(),
  };
}

function annotateGameEmployeesForAccount(employees = [], gameData = {}) {
  return (Array.isArray(employees) ? employees : []).map((employee) => ({
    ...employee,
    currentAssignment: createEmployeeAssignmentFromGame(employee, gameData),
  }));
}

function normalizeEmployeeGrowthBaseForAccountSync(employee) {
  const level = Math.max(1, Math.round(Number(employee?.level) || 1));
  const awakeningMax = 5;
  const awakening = Math.max(0, Math.min(awakeningMax, Math.round(Number(employee?.awakening) || 0)));
  return {
    ...employee,
    level,
    exp: Math.max(0, Math.round(Number(employee?.exp) || 0)),
    awakening,
    baseLeadership: employee?.baseLeadership ?? employee?.leadership ?? 0,
    baseSales: employee?.baseSales ?? employee?.sales ?? 0,
    baseConstruction: employee?.baseConstruction ?? employee?.construction ?? 0,
    baseManagement: employee?.baseManagement ?? employee?.management ?? 0,
    baseSalary: BASE_EMPLOYEE_SALARY,
    salary: calculateEmployeeSalaryByLevel(level),
    qualifications: normalizeQualificationList(employee?.qualifications),
  };
}

function applyAccountGrowthToEmployee(employee, accountEmployee) {
  if (!employee || !accountEmployee) return employee;
  const normalizedAccountEmployee = normalizeAccountEmployee(accountEmployee);
  if (!normalizedAccountEmployee) return employee;
  const localOfficeId = employee.officeId ?? null;
  return normalizeEmployeeGrowthBaseForAccountSync({
    ...employee,
    level: Math.max(Number(employee.level) || 1, Number(normalizedAccountEmployee.level) || 1),
    exp: Math.max(Number(employee.exp) || 0, Number(normalizedAccountEmployee.exp) || 0),
    awakening: Math.max(Number(employee.awakening) || 0, Number(normalizedAccountEmployee.awakening) || 0),
    leadership: Math.max(Number(employee.leadership) || 0, Number(normalizedAccountEmployee.leadership) || 0),
    sales: Math.max(Number(employee.sales) || 0, Number(normalizedAccountEmployee.sales) || 0),
    construction: Math.max(Number(employee.construction) || 0, Number(normalizedAccountEmployee.construction) || 0),
    management: Math.max(Number(employee.management) || 0, Number(normalizedAccountEmployee.management) || 0),
    baseLeadership: Math.max(Number(employee.baseLeadership ?? employee.leadership) || 0, Number(normalizedAccountEmployee.baseLeadership ?? normalizedAccountEmployee.leadership) || 0),
    baseSales: Math.max(Number(employee.baseSales ?? employee.sales) || 0, Number(normalizedAccountEmployee.baseSales ?? normalizedAccountEmployee.sales) || 0),
    baseConstruction: Math.max(Number(employee.baseConstruction ?? employee.construction) || 0, Number(normalizedAccountEmployee.baseConstruction ?? normalizedAccountEmployee.construction) || 0),
    baseManagement: Math.max(Number(employee.baseManagement ?? employee.management) || 0, Number(normalizedAccountEmployee.baseManagement ?? normalizedAccountEmployee.management) || 0),
    qualifications: normalizeQualificationList([
      ...(Array.isArray(employee.qualifications) ? employee.qualifications : []),
      ...(Array.isArray(normalizedAccountEmployee.qualifications) ? normalizedAccountEmployee.qualifications : []),
    ]),
    salary: calculateEmployeeSalaryByLevel(Math.max(Number(employee.level) || 1, Number(normalizedAccountEmployee.level) || 1)),
    officeId: localOfficeId,
  });
}

function syncEmployeeListWithAccountVault(employeeList = [], accountData = {}) {
  const vault = Array.isArray(accountData?.employeeVault) ? accountData.employeeVault : [];
  const vaultMap = new Map(vault.map((employee) => [Number(employee?.id), employee]));
  return (Array.isArray(employeeList) ? employeeList : []).map((employee) => {
    const accountEmployee = vaultMap.get(Number(employee?.id));
    return accountEmployee ? applyAccountGrowthToEmployee(employee, accountEmployee) : employee;
  });
}

function normalizeFounderEmployeeForNewCompany(employee) {
  const normalizedEmployee = normalizeAccountEmployee(employee);

  if (!normalizedEmployee) return null;

  return {
    ...normalizedEmployee,
    officeId: "hq",
    busyUntilMonth: null,
    busyActionName: null,
    founderCarryOver: true,
  };
}

function mergeEmployeeCollections(...employeeLists) {
  const employeeMap = new Map();

  employeeLists.flat().forEach((employee) => {
    const normalizedEmployee = normalizeAccountEmployee(employee);
    if (!normalizedEmployee) return;

    const currentEmployee = employeeMap.get(normalizedEmployee.id);
    if (!currentEmployee) {
      employeeMap.set(normalizedEmployee.id, normalizedEmployee);
      return;
    }

    const nextEmployee = getComparableEmployeePower(normalizedEmployee) >= getComparableEmployeePower(currentEmployee)
      ? {
          ...normalizedEmployee,
          currentAssignment: normalizedEmployee.currentAssignment ?? currentEmployee.currentAssignment ?? null,
        }
      : {
          ...currentEmployee,
          currentAssignment: currentEmployee.currentAssignment ?? normalizedEmployee.currentAssignment ?? null,
        };
    employeeMap.set(normalizedEmployee.id, nextEmployee);
  });

  return Array.from(employeeMap.values());
}

function getBetterAccountRankExp(accountData, rank, exp) {
  const accountRank = Math.max(1, Math.round(Number(accountData?.playerRank) || 1));
  const accountExp = Math.max(0, Math.round(Number(accountData?.playerExp) || 0));
  const incomingRank = Math.max(1, Math.round(Number(rank) || 1));
  const incomingExp = Math.max(0, Math.round(Number(exp) || 0));

  if (incomingRank > accountRank) return { playerRank: incomingRank, playerExp: incomingExp };
  if (incomingRank < accountRank) return { playerRank: accountRank, playerExp: accountExp };

  return { playerRank: accountRank, playerExp: Math.max(accountExp, incomingExp) };
}

function mergeAccountDataWithGame(accountData, gameData = {}) {
  const rankExp = getBetterAccountRankExp(accountData, gameData.playerRank, gameData.playerExp);
  const gameEmployeesForAccount = annotateGameEmployeesForAccount(gameData.employees ?? [], gameData);
  const storageEmployeesForAccount = annotateGameEmployeesForAccount(gameData.employeeStorage ?? [], { ...gameData, currentGameMode: null, freeMapKey: null, areaLabel: "保管庫" });

  // v363.8: フリーマップは「1マップ1セーブ」。同じ地域を最初から開始して保存したら、
  // その地域の古い配属情報は消す。これで旧名古屋支店所属が新データに残らない。
  const currentAreaKey = getSpecialMissionAreaKeyFromMode(gameData.currentGameMode, gameData.freeMapKey);
  const accountVaultForMerge = (accountData?.employeeVault ?? []).map((employee) => {
    const assignment = employee?.currentAssignment;
    if (!assignment || !currentAreaKey || currentAreaKey === "unknown") return employee;
    const assignmentAreaKey = getSpecialMissionAreaKeyFromMode(assignment.mode, assignment.freeMapKey);
    if (assignmentAreaKey !== currentAreaKey) return employee;
    return { ...employee, currentAssignment: null, officeId: null, busyUntilMonth: null, busyActionName: null };
  });

  const employeeVault = mergeEmployeeCollections(
    accountVaultForMerge,
    gameEmployeesForAccount,
    storageEmployeesForAccount
  );
  const currentTickets = getAccountTicketCounts(accountData);

  return {
    playerRank: rankExp.playerRank,
    playerExp: rankExp.playerExp,
    employeeVault,
    unlockedStoryAkari: accountData?.unlockedStoryAkari === true ||
      employeeVault.some((employee) => employee.id === 122) ||
      gameData.hasClearedGifuChapter === true ||
      gameData.hasClearedNagoyaChapter === true ||
      gameData.hasClearedKyotoChapter === true ||
      gameData.hasClearedOsakaChapter === true ||
      gameData.hasClearedTokyoChapter === true,
    hasClearedGifuChapter: accountData?.hasClearedGifuChapter === true || gameData.hasClearedGifuChapter === true,
    hasClearedNagoyaChapter: accountData?.hasClearedNagoyaChapter === true || gameData.hasClearedNagoyaChapter === true,
    hasClearedKyotoChapter: accountData?.hasClearedKyotoChapter === true || gameData.hasClearedKyotoChapter === true,
    hasClearedOsakaChapter: accountData?.hasClearedOsakaChapter === true || gameData.hasClearedOsakaChapter === true,
    hasClearedTokyoChapter: accountData?.hasClearedTokyoChapter === true || gameData.hasClearedTokyoChapter === true,
    hasCompletedKyotoTourismTutorial: accountData?.hasCompletedKyotoTourismTutorial === true || gameData.hasCompletedKyotoTourismTutorial === true,
    hasCompletedOsakaIndustrialTutorial: accountData?.hasCompletedOsakaIndustrialTutorial === true || gameData.hasCompletedOsakaIndustrialTutorial === true,
    rookieEmployeeTickets: Math.max(0, Math.round(Number(gameData.rookieEmployeeTickets ?? currentTickets.rookieEmployeeTickets) || 0)),
    employeeTickets: Math.max(0, Math.round(Number(gameData.employeeTickets ?? currentTickets.employeeTickets) || 0)),
    premiumEmployeeTickets: Math.max(0, Math.round(Number(gameData.premiumEmployeeTickets ?? currentTickets.premiumEmployeeTickets) || 0)),
    medals: Math.max(0, Math.round(Number(accountData?.medals ?? accountData?.medal ?? 0) || 0)),
    shine: Math.max(0, Math.round(Number(accountData?.shine ?? accountData?.shines ?? 0) || 0)),
    silverSheets: 0,
    goldSheets: 0,
    rainbowSheets: 0,
    specialMissionData: accountData?.specialMissionData && typeof accountData.specialMissionData === "object" ? accountData.specialMissionData : null,
    items: accountData?.items && typeof accountData.items === "object" ? Object.fromEntries(Object.entries(accountData.items).map(([key, value]) => [key, Math.max(0, Math.round(Number(value) || 0))])) : {},
    usedSecretCommands: accountData?.usedSecretCommands && typeof accountData.usedSecretCommands === "object" ? accountData.usedSecretCommands : {},
    [DEV_DEMO_SHEET_GRANT_KEY]: true,
    updatedAt: new Date().toISOString(),
  };
}

function getEmployeeFromAccountVault(accountData, employeeId) {
  const targetId = Number(employeeId);
  if (!Number.isFinite(targetId)) return null;

  const employeeVault = Array.isArray(accountData?.employeeVault) ? accountData.employeeVault : [];
  const found = employeeVault.find((employee) => Number(employee?.id) === targetId);
  return found ? normalizeAccountEmployee(found) : null;
}

function getStoryAkariForFounder(accountData) {
  const savedAkari = getEmployeeFromAccountVault(accountData, 122);
  if (savedAkari) return savedAkari;
  if (accountData?.unlockedStoryAkari === true) return normalizeAccountEmployee(createStoryAkari());
  return null;
}

function getFounderEmployeesFromAccount(accountData, selectedEmployeeIds = []) {
  const uniqueSelectedIds = Array.from(new Set(selectedEmployeeIds.map((id) => Number(id)).filter((id) => Number.isFinite(id))));
  const founderEmployees = [];
  uniqueSelectedIds.forEach((employeeId) => {
    const employee = getEmployeeFromAccountVault(accountData, employeeId)
      ?? (employeeId === 122 ? getStoryAkariForFounder(accountData) : null);
    if (!employee) return;
    founderEmployees.push({
      ...employee,
      officeId: "hq",
    });
  });

  return founderEmployees
    .map((employee) => normalizeFounderEmployeeForNewCompany(employee))
    .filter(Boolean);
}

function getFounderSelectableEmployees(accountData) {
  const employeeVault = Array.isArray(accountData?.employeeVault) ? accountData.employeeVault : [];
  const akari = getStoryAkariForFounder(accountData);
  const sourceEmployees = akari ? [akari, ...employeeVault] : employeeVault;
  return mergeEmployeeCollections(sourceEmployees)
    .sort((a, b) => {
      const rarityOrder = { UR: 6, SSR: 5, SR: 4, HR: 3, R: 2, N: 1 };
      const rarityDiff = (rarityOrder[b.rarity] ?? 0) - (rarityOrder[a.rarity] ?? 0);
      if (rarityDiff !== 0) return rarityDiff;
      return getComparableEmployeePower(b) - getComparableEmployeePower(a);
    });
}

function isEmployeeAssignedToAnotherMap(employee) {
  return Boolean(employee?.currentAssignment && employee.currentAssignment.areaLabel && employee.currentAssignment.areaLabel !== "保管庫");
}

function getEmployeeAssignmentStatusText(employee) {
  if (!employee?.currentAssignment) return "待機";
  return getEmployeeAssignmentLabel(employee.currentAssignment);
}


