const EMPLOYEE_POOL = employeeMaster;

const MAX_EMPLOYEES_PER_OFFICE = 10;
const EMPLOYEE_RECRUITMENT_ENVELOPE_COUNT = 4;
const EMPLOYEE_AWAKENING_MAX = 5;
