const BRANCH_OFFICE_BASE_MONTHS = 6;
const HQ_ACTION_RANGE = 10;
const BRANCH_ACTION_RANGE = 10;
const OFFICE_MIN_DISTANCE = 0;

function randomInt(min, max) {
  return Math.floor(Math.random() * (max - min + 1)) + min;
}

function getDistance(x1, y1, x2, y2) {
  return Math.abs(x1 - x2) + Math.abs(y1 - y2);
}

function getNearestPointDistance(x, y, points, fallbackX, fallbackY) {
  if (Array.isArray(points) && points.length > 0) {
    return Math.min(
      ...points.map((point) => getDistance(x, y, point.x, point.y))
    );
  }

  if (fallbackX == null || fallbackY == null) return Number.POSITIVE_INFINITY;

  return getDistance(x, y, fallbackX, fallbackY);
}

const ZONE_INFLUENCE_RANGE = 2;

function getFacilityInfluenceType(feature) {
  if (feature === FEATURE.STATION) return ZONE.COMMERCIAL;
  if (feature === FEATURE.FACTORY) return ZONE.INDUSTRIAL;
  if (feature === FEATURE.SCHOOL) return ZONE.RESIDENTIAL;
  return null;
}

function isIndustrialBuildingKey(buildingKey) {
  const buildingInfo = BUILDINGS?.[buildingKey];
  return Boolean(buildingKey && (buildingInfo?.category === "工業" || String(buildingKey).includes("factory") || buildingKey === "warehouse"));
}

function getZoneFromFacilityInfluencers(x, y, stationPoints = [], factoryPoints = [], schoolPoints = []) {
  const stationDistance = getNearestPointDistance(x, y, stationPoints, null, null);
  const factoryDistance = getNearestPointDistance(x, y, factoryPoints, null, null);
  const schoolDistance = getNearestPointDistance(x, y, schoolPoints, null, null);

  if (stationDistance <= ZONE_INFLUENCE_RANGE) return ZONE.COMMERCIAL;
  if (factoryDistance <= ZONE_INFLUENCE_RANGE) return ZONE.INDUSTRIAL;
  if (schoolDistance <= ZONE_INFLUENCE_RANGE) return ZONE.RESIDENTIAL;

  return ZONE.GENERAL;
}

function collectZoneInfluencersFromTiles(tiles = []) {
  const stationPoints = [];
  const factoryPoints = [];
  const schoolPoints = [];

  tiles.forEach((tile) => {
    if (!tile) return;

    if (tile.feature === FEATURE.STATION) stationPoints.push({ x: tile.x, y: tile.y });
    if (tile.feature === FEATURE.SCHOOL) schoolPoints.push({ x: tile.x, y: tile.y });
    if (tile.feature === FEATURE.FACTORY || isIndustrialBuildingKey(tile.building)) {
      factoryPoints.push({ x: tile.x, y: tile.y });
    }
  });

  return { stationPoints, factoryPoints, schoolPoints };
}

function recalculateTileZonesByFacilities(tiles = []) {
  const { stationPoints, factoryPoints, schoolPoints } = collectZoneInfluencersFromTiles(tiles);

  return tiles.map((tile) => ({
    ...tile,
    zone: getZoneFromFacilityInfluencers(tile.x, tile.y, stationPoints, factoryPoints, schoolPoints),
  }));
}

function getFacilityInfluenceZoneForTile(tile) {
  if (!tile) return null;
  if (tile.feature === FEATURE.STATION) return ZONE.COMMERCIAL;
  if (tile.feature === FEATURE.SCHOOL) return ZONE.RESIDENTIAL;
  if (tile.feature === FEATURE.FACTORY || isIndustrialBuildingKey(tile.building)) return ZONE.INDUSTRIAL;
  return null;
}


function isBuildableTile(tile) {
  if (!tile) return false;
  if (tile.terrain !== TERRAIN.PLAIN) return false;
  if (tile.feature !== FEATURE.NONE) return false;
  // 線路上は建設不可。線路沿いは可だが、線路そのものには本社・支店・建物を置かない。
  if (tile.rail === true) return false;
  return true;
}

function isRailTileForStationPlacement(tile) {
  // 駅新設だけは線路上に置くため、通常建設判定とは分ける。
  return !!tile &&
    tile.terrain === TERRAIN.PLAIN &&
    tile.rail === true &&
    tile.feature === FEATURE.NONE &&
    !tile.building &&
    !tile.buildingMainId;
}

function sanitizeMapForV138(mapData) {
  if (!mapData || !Array.isArray(mapData.tiles)) return mapData;

  const cleanedTiles = mapData.tiles.map((tile) => {
      const invalidFacilityOnNonPlain =
        tile.terrain !== TERRAIN.PLAIN &&
        (tile.feature === FEATURE.STATION || tile.feature === FEATURE.FACTORY || tile.feature === FEATURE.SCHOOL);

      const invalidGeneralHqApartment =
        tile.building === "hq_apartment" &&
        !(tile.feature === FEATURE.HQ && (tile.owner === OWNER.PLAYER || tile.owner === OWNER.RIVAL));

      if (!invalidFacilityOnNonPlain && !invalidGeneralHqApartment) return tile;

      return {
        ...tile,
        feature: invalidFacilityOnNonPlain ? FEATURE.NONE : tile.feature,
        rail: invalidFacilityOnNonPlain && tile.feature === FEATURE.STATION ? false : tile.rail,
        building: null,
        buildingMainId: null,
        rooms: [],
      };
    });

  return {
    ...mapData,
    tiles: recalculateTileZonesByFacilities(cleanedTiles),
  };
}

function calculateLandPrice(
  x,
  y,
  terrain,
  feature,
  stationX,
  stationY,
  schoolX,
  schoolY,
  factoryX,
  factoryY
) {
  const stationDistance = getNearestPointDistance(x, y, stationX, stationX, stationY);
  const schoolDistance = getNearestPointDistance(x, y, schoolX, schoolX, schoolY);
  const factoryDistance = getDistance(x, y, factoryX, factoryY);

  let price = 500;

  price += Math.max(0, 12000 - stationDistance * 1200);
  price += Math.max(0, 1800 - schoolDistance * 180);
  price += Math.max(0, 1200 - factoryDistance * 120);

  if (feature === FEATURE.ROAD) price += 500;
  if (feature === FEATURE.STATION) price += 3000;
  if (feature === FEATURE.SCHOOL) price += 800;
  if (feature === FEATURE.FACTORY) price += 500;

  if (terrain === TERRAIN.MOUNTAIN) price = 200;
  if (terrain === TERRAIN.RIVER) price = 300;
  if (terrain === TERRAIN.SEA) price = 400;

  return Math.round(price);
}
function getZone(x, y, stationX, stationY, schoolX, schoolY, factoryX, factoryY) {
  const stationPoints = Array.isArray(stationX) ? stationX : (stationX != null && stationY != null ? [{ x: stationX, y: stationY }] : []);
  const schoolPoints = Array.isArray(schoolX) ? schoolX : (schoolX != null && schoolY != null ? [{ x: schoolX, y: schoolY }] : []);
  const factoryPoints = Array.isArray(factoryX) ? factoryX : (factoryX != null && factoryY != null ? [{ x: factoryX, y: factoryY }] : []);

  // v234: 用途地域の影響範囲は、駅・学校・工場の施設マスから周囲2マスまでに固定。
  // 学校のような2×2施設は、4マスそれぞれを起点にして2マスだけ住宅地域にする。
  return getZoneFromFacilityInfluencers(x, y, stationPoints, factoryPoints, schoolPoints);
}

function createRooms(buildingKey, demand, currentMonth = 0) {
  const building = BUILDINGS[buildingKey];

  return Array.from({ length: building.rooms }, (_, index) => {
    const shouldOccupy = Math.random() * 100 < demand * 0.55;

    if (!shouldOccupy) {
      return {
        roomNo: index + 1,
        tenantType: null,
        people: 0,
        rent: building.baseRent,
        contractRent: null,
        contractStartMonth: null,
        lastRentReviewMonth: null,
        occupied: false,
        tenantMonths: 0,
      };
    }

    const tenantKey =
      building.allowedTenants[randomInt(0, building.allowedTenants.length - 1)];
    const tenant = TENANT_TYPES[tenantKey];
    const people = randomInt(tenant.peopleMin, tenant.peopleMax);
    const rent = Math.round(building.baseRent * tenant.rentPower);

    return {
      roomNo: index + 1,
      tenantType: tenantKey,
      people,
      rent,
      contractRent: rent,
      contractStartMonth: currentMonth,
      lastRentReviewMonth: currentMonth,
      occupied: true,
      tenantMonths: 0,
    };
  });
}

function getOwnedEmployeeIdsForRivalExclusion() {
  try {
    const accountData = readAccountData();
    const ids = new Set();
    const sources = [
      ...(Array.isArray(accountData?.employeeVault) ? accountData.employeeVault : []),
      ...(Array.isArray(accountData?.employees) ? accountData.employees : []),
    ];
    sources.forEach((employee) => {
      const id = employee?.sourceEmployeeId ?? employee?.originalEmployeeId ?? employee?.id;
      if (id !== undefined && id !== null) ids.add(String(id));
    });
    return ids;
  } catch (error) {
    return new Set();
  }
}

function getRivalRecruitTicketTypeByRank(rank = 1) {
  const safeRank = Math.max(1, Math.round(Number(rank) || 1));
  if (safeRank % 10 === 0) return "premium";
  if (safeRank % 5 === 0) return "normal";
  return "rookie";
}

function getRivalRecruitTicketLabel(ticketType = "rookie") {
  if (ticketType === "premium") return "プレミア社員採用チケット";
  if (ticketType === "normal") return "レア社員採用チケット";
  return "社員採用チケット";
}

const RIVAL_RARITY_SCORE = { N: 1, R: 2, HR: 3, SR: 4, SSR: 5, UR: 6 };

function getRivalEmployeeAbilityTotal(employee = {}) {
  return ["leadership", "sales", "construction", "management"].reduce((sum, key) => {
    return sum + Math.max(0, Number(employee?.[key] ?? employee?.[`base${key[0].toUpperCase()}${key.slice(1)}`] ?? 0) || 0);
  }, 0);
}

function sortRivalEmployeesByPriority(employeeList = []) {
  return [...(Array.isArray(employeeList) ? employeeList : [])].sort((a, b) => {
    const rarityDiff = (RIVAL_RARITY_SCORE[b?.rarity] ?? 0) - (RIVAL_RARITY_SCORE[a?.rarity] ?? 0);
    if (rarityDiff !== 0) return rarityDiff;
    const abilityDiff = getRivalEmployeeAbilityTotal(b) - getRivalEmployeeAbilityTotal(a);
    if (abilityDiff !== 0) return abilityDiff;
    return String(a?.name ?? "").localeCompare(String(b?.name ?? ""), "ja");
  });
}

function removeBankruptRivalCompany(tileList = [], companyId = "A") {
  return tileList.map((tile) => {
    if (tile.owner !== OWNER.RIVAL || tile.rivalCompanyId !== companyId) return tile;
    return {
      ...tile,
      owner: tile.terrain === TERRAIN.PLAIN && tile.feature !== FEATURE.ROAD && tile.feature !== FEATURE.STATION && tile.feature !== FEATURE.SCHOOL && !tile.rail ? OWNER.SALE : OWNER.PUBLIC,
      feature: tile.feature === FEATURE.HQ || tile.feature === FEATURE.BRANCH ? FEATURE.NONE : tile.feature,
      building: null,
      buildingMainId: null,
      rooms: [],
      rivalCompanyId: null,
      rivalCompanyName: null,
      rivalOfficeId: null,
      rivalOfficeName: null,
      rivalEmployees: null,
      rivalMoney: null,
      rivalAgeMonths: null,
      rivalSixMonthTicketGranted: null,
      rivalRank: null,
    };
  });
}

function drawRivalRecruitRarity(ticketType = "rookie") {
  const roll = Math.random() * 100;

  if (ticketType === "premium") {
    if (roll < 79.4) return "SR";
    if (roll < 95.3) return "SSR";
    return "UR";
  }

  if (ticketType === "normal") {
    if (roll < 61.7) return "N";
    if (roll < 83.7) return "R";
    if (roll < 93.7) return "HR";
    if (roll < 98.7) return "SR";
    if (roll < 99.7) return "SSR";
    return "UR";
  }

  if (roll < 71.9) return "N";
  if (roll < 93.9) return "R";
  if (roll < 98.9) return "HR";
  if (roll < 99.9) return "SR";
  return "SSR";
}

function pickRivalInitialEmployee(ticketType = "rookie", excludeSourceIds = []) {
  const ownedIds = getOwnedEmployeeIdsForRivalExclusion();
  const excludeIds = new Set([...Array.from(ownedIds), ...excludeSourceIds.map((id) => String(id))]);

  let picked = null;
  for (let attempt = 0; attempt < 24; attempt += 1) {
    const rarity = drawRivalRecruitRarity(ticketType);
    let pool = EMPLOYEE_POOL.filter((employee) => {
      return employee.rarity === rarity && !excludeIds.has(String(employee.id));
    });
    if (pool.length === 0) {
      pool = EMPLOYEE_POOL.filter((employee) => employee.rarity === rarity);
    }
    if (pool.length > 0) {
      picked = pool[randomInt(0, pool.length - 1)];
      break;
    }
  }

  if (!picked) {
    const fallbackPool = EMPLOYEE_POOL.filter((employee) => !excludeIds.has(String(employee.id)));
    const pool = fallbackPool.length > 0 ? fallbackPool : EMPLOYEE_POOL;
    picked = pool[randomInt(0, pool.length - 1)];
  }

  const uniqueSuffix = `${Date.now()}_${Math.random().toString(36).slice(2, 8)}`;
  return {
    ...structuredClone(picked),
    id: `rival_${picked.id}_${uniqueSuffix}`,
    sourceEmployeeId: picked.id,
    originalEmployeeId: picked.id,
    baseLeadership: picked.baseLeadership ?? picked.leadership ?? 0,
    baseSales: picked.baseSales ?? picked.sales ?? 0,
    baseConstruction: picked.baseConstruction ?? picked.construction ?? 0,
    baseManagement: picked.baseManagement ?? picked.management ?? 0,
    baseSalary: BASE_EMPLOYEE_SALARY,
    level: 1,
    exp: 0,
    salary: calculateEmployeeSalaryByLevel(1),
    officeId: "rival_A_hq",
  };
}

function isTileNearRoadOrRail(tile, tiles) {
  return tiles.some((otherTile) => {
    if (getDistance(tile.x, tile.y, otherTile.x, otherTile.y) !== 1) return false;
    return otherTile.feature === FEATURE.ROAD || otherTile.rail === true;
  });
}



function placeStoryRivalOffice(tiles, companyId = "A", companyName = "ライバル不動産", preferredPositions = []) {
  if (!Array.isArray(tiles) || tiles.length === 0) return;
  const preferredKeys = new Set(preferredPositions.map((pos) => `${pos.x},${pos.y}`));
  const preferredCandidates = tiles.filter((tile) => {
    return preferredKeys.has(`${tile.x},${tile.y}`) &&
      tile.terrain === TERRAIN.PLAIN &&
      tile.feature === FEATURE.NONE &&
      !tile.rail &&
      !tile.building &&
      !tile.buildingMainId &&
      tile.owner !== OWNER.PLAYER &&
      tile.owner !== OWNER.PUBLIC;
  });
  const fallbackCandidates = tiles.filter((tile) => {
    return tile.terrain === TERRAIN.PLAIN &&
      tile.feature === FEATURE.NONE &&
      !tile.rail &&
      !tile.building &&
      !tile.buildingMainId &&
      tile.owner === OWNER.SALE;
  });
  const candidatePool = preferredCandidates.length > 0 ? preferredCandidates : fallbackCandidates;
  const rivalOfficeTile = candidatePool[0];
  if (!rivalOfficeTile) return;
  const company = getRivalCompany(companyId);
  const rivalEmployee = {
    ...pickRivalInitialEmployee("rookie"),
    officeId: `rival_${company.id}_hq`,
  };
  rivalOfficeTile.owner = OWNER.RIVAL;
  rivalOfficeTile.feature = FEATURE.HQ;
  rivalOfficeTile.building = null;
  rivalOfficeTile.buildingMainId = null;
  rivalOfficeTile.rooms = [];
  rivalOfficeTile.rivalCompanyId = company.id;
  rivalOfficeTile.rivalCompanyName = companyName || company.name;
  rivalOfficeTile.rivalOfficeName = `${rivalOfficeTile.rivalCompanyName} 本社`;
  rivalOfficeTile.rivalEmployees = [rivalEmployee];
  rivalOfficeTile.rivalMoney = company.initialMoney;
}

function createKyotoStoryMap() {
  const size = 30;
  const stationX = 14;
  const stationY = 18;
  const stationPositions = [{ x: stationX, y: stationY, name: "京都駅" }];
  const schoolPositions = [
    { x: 10, y: 15, name: "中央の学校" },
    { x: 20, y: 12, name: "東山の学校" },
  ];
  const factoryPositions = [];
  const roadSet = new Set();
  const railSet = new Set();
  const riverSet = new Set();
  const mountainSet = new Set();
  const fixedTourismSet = new Map();
  const fixedBuildings = new Map();
  const tiles = [];

  function addRoad(x, y) { if (x >= 0 && x < size && y >= 0 && y < size) roadSet.add(`${x},${y}`); }
  function addRail(x, y) { if (x >= 0 && x < size && y >= 0 && y < size) railSet.add(`${x},${y}`); }
  function addRiver(x, y) { if (x >= 0 && x < size && y >= 0 && y < size) riverSet.add(`${x},${y}`); }
  function addMountain(x, y) { if (x >= 0 && x < size && y >= 0 && y < size) mountainSet.add(`${x},${y}`); }
  function addFixedTourism(x, y, label, building = "souvenir_shop") {
    fixedTourismSet.set(`${x},${y}`, { label, building });
  }
  function addFixedBuilding(x, y, data) { fixedBuildings.set(`${x},${y}`, data); }

  for (let x = 0; x < size; x++) addRail(x, stationY);
  for (let y = 8; y <= 27; y++) addRail(stationX, y);

  [7, 14, 22].forEach((x) => { for (let y = 5; y < size; y++) addRoad(x, y); });
  [10, 16, 23, 26].forEach((y) => { for (let x = 2; x < size - 2; x++) addRoad(x, y); });

  for (let y = 5; y < size; y++) {
    const curveX = 5 + Math.round(Math.sin(y * 0.45) * 1.5);
    addRiver(curveX, y);
    if (y % 4 === 0) addRiver(curveX + 1, y);
  }

  for (let y = 0; y <= 5; y++) {
    for (let x = 0; x < size; x++) {
      if (y <= 3 || x < 4 || x > 25 || (x + y) % 3 === 0) addMountain(x, y);
    }
  }
  for (let y = 6; y <= 12; y++) {
    for (let x = 0; x <= 3; x++) addMountain(x, y);
    for (let x = 26; x < size; x++) addMountain(x, y);
  }

  addFixedTourism(4, 13, "竹林公園", "ryokan");
  addFixedTourism(7, 7, "渓流温泉地", "hot_spring");
  addFixedTourism(22, 9, "黄金寺院", "souvenir_shop");
  addFixedTourism(25, 15, "千本鳥居神社", "souvenir_shop");
  addFixedTourism(20, 18, "歴史庭園", "ryokan");

  addFixedBuilding(12, 19, { owner: OWNER.SALE, building: null, landPrice: 420 });
  addFixedBuilding(16, 19, { owner: OWNER.SALE, building: null, landPrice: 440 });
  addFixedBuilding(10, 17, { owner: OWNER.OTHER, building: "small_shop", rent: 105, age: 7, condition: 82, landPrice: 390 });
  addFixedBuilding(18, 20, { owner: OWNER.OTHER, building: "convenience", rent: 115, age: 5, condition: 86, landPrice: 410 });
  addFixedBuilding(8, 18, { owner: OWNER.SALE, building: null, landPrice: 320 });
  addFixedBuilding(23, 17, { owner: OWNER.SALE, building: null, landPrice: 340 });
  addFixedBuilding(4, 16, { owner: OWNER.SALE, building: null, landPrice: 260 });
  addFixedBuilding(6, 12, { owner: OWNER.OTHER, building: "ryokan", rent: 120, age: 16, condition: 74, landPrice: 330 });
  addFixedBuilding(21, 20, { owner: OWNER.OTHER, building: "souvenir_shop", rent: 72, age: 10, condition: 80, landPrice: 300 });

  function getKyotoZone(x, y) {
    if (getDistance(x, y, stationX, stationY) <= 4) return ZONE.COMMERCIAL;
    if (x >= 20 && y >= 7 && y <= 20) return ZONE.COMMERCIAL;
    if (x <= 8 && y >= 10 && y <= 18) return ZONE.COMMERCIAL;
    if (y >= 12 && y <= 22) return ZONE.RESIDENTIAL;
    return ZONE.GENERAL;
  }

  for (let y = 0; y < size; y++) {
    for (let x = 0; x < size; x++) {
      const key = `${x},${y}`;
      const rail = railSet.has(key);
      let terrain = TERRAIN.PLAIN;
      let feature = FEATURE.NONE;
      let owner = OWNER.OTHER;
      let building = null;
      let rooms = [];
      let age = 0;
      let condition = 100;
      let zone = getKyotoZone(x, y);
      let landPrice = 170 + Math.max(0, 12 - getDistance(x, y, stationX, stationY)) * 18;
      const fixedTourism = fixedTourismSet.get(key);
      const fixed = fixedBuildings.get(key);

      if (mountainSet.has(key)) {
        terrain = TERRAIN.MOUNTAIN;
        owner = OWNER.PUBLIC;
        landPrice = 80;
      }

      if (riverSet.has(key)) {
        terrain = TERRAIN.RIVER;
        owner = OWNER.PUBLIC;
        landPrice = 70;
      }

      if (fixed) {
        owner = fixed.owner;
        building = fixed.building;
        age = fixed.age ?? 0;
        condition = fixed.condition ?? 100;
        landPrice = fixed.landPrice ?? landPrice;
        rooms = building ? createRooms(building, fixed.rent ?? 80, 0) : [];
      }

      if (roadSet.has(key)) {
        feature = FEATURE.ROAD;
        owner = OWNER.PUBLIC;
        building = null;
        rooms = [];
        age = 0;
        condition = 100;
        terrain = TERRAIN.PLAIN;
        landPrice += 35;
      }

      if (rail) {
        feature = FEATURE.NONE;
        owner = OWNER.PUBLIC;
        building = null;
        rooms = [];
        age = 0;
        condition = 100;
        terrain = TERRAIN.PLAIN;
      }

      if (x === stationX && y === stationY) {
        feature = FEATURE.STATION;
        owner = OWNER.PUBLIC;
        building = null;
        rooms = [];
        age = 0;
        condition = 100;
        terrain = TERRAIN.PLAIN;
        landPrice += 260;
        zone = ZONE.COMMERCIAL;
      }

      const school = schoolPositions.find((point) => point.x === x && point.y === y);
      if (school) {
        feature = FEATURE.SCHOOL;
        owner = OWNER.PUBLIC;
        building = null;
        rooms = [];
        age = 0;
        condition = 100;
        terrain = TERRAIN.PLAIN;
        landPrice += 70;
        zone = ZONE.RESIDENTIAL;
      }

      if (fixedTourism) {
        owner = OWNER.PUBLIC;
        building = fixedTourism.building;
        rooms = createRooms(fixedTourism.building, 0, 0);
        age = 0;
        condition = 100;
        terrain = TERRAIN.PLAIN;
        landPrice += 180;
        zone = ZONE.COMMERCIAL;
      }

      if (
        owner === OWNER.OTHER &&
        !building &&
        feature === FEATURE.NONE &&
        terrain === TERRAIN.PLAIN &&
        !rail &&
        ((x * 19 + y * 23) % 5 === 0)
      ) {
        owner = OWNER.SALE;
      }

      tiles.push({
        id: y * size + x,
        x,
        y,
        terrain,
        feature,
        rail,
        zone,
        owner,
        building,
        buildingMainId: null,
        rooms,
        age,
        condition,
        vacancyMonths: 0,
        recoveryMode: false,
        landPrice: Math.max(70, landPrice),
        tourismName: fixedTourism?.label ?? null,
      });
    }
  }

  placeStoryRivalOffice(tiles, "B", KYOTO_RIVAL_COMPANY_NAME, [
    { x: 24, y: 18 },
    { x: 22, y: 20 },
    { x: 18, y: 22 },
  ]);

  return {
    tiles: recalculateTileZonesByFacilities(tiles),
    stationX,
    stationY,
    stationPositions,
    schoolX: schoolPositions[0].x,
    schoolY: schoolPositions[0].y,
    schoolPositions,
    factoryX: null,
    factoryY: null,
    factoryPositions,
  };
}

function createMap(freeMapMode = "free_70") {
if (normalizeFreeModeKey(freeMapMode) === "free_kyoto") {
  return createKyotoStoryMap();
}
const mapOption = getFreeMapOption(freeMapMode);
const mapSize = mapOption.size;
const hasSea = mapSize >= 50;
const targetSchoolCount = mapSize <= 15 ? 1 : mapSize <= 30 ? 3 : mapSize <= 50 ? 5 : randomInt(4, 6);
const hasFactory = true;
const mapMargin = mapSize <= 15 ? 2 : mapSize <= 30 ? 3 : 5;
const innerMin = mapMargin;
const innerMax = Math.max(innerMin, mapSize - mapMargin - 1);
function randomInnerCoordinate() { return randomInt(innerMin, innerMax); }
const seaSide = randomInt(0, 3);
const seaStart = randomInt(Math.floor(mapSize * 0.78), Math.floor(mapSize * 0.86));

function getCoastOffset(index) {
  return Math.round(Math.sin(index * 0.45) * 2);
}

function isSeaCoordinate(x, y) {
  if (!hasSea) return false;
  const coastOffset =
    seaSide === 0 || seaSide === 1
      ? getCoastOffset(y)
      : getCoastOffset(x);

  return (
    (seaSide === 0 && x >= seaStart + coastOffset) ||
    (seaSide === 1 && x <= mapSize - seaStart + coastOffset) ||
    (seaSide === 2 && y >= seaStart + coastOffset) ||
    (seaSide === 3 && y <= mapSize - seaStart + coastOffset)
  );
}

function createRandomPoint(minDistance, usedPoints = []) {
  for (let attempt = 0; attempt < 200; attempt++) {
    const point = {
      x: randomInnerCoordinate(),
      y: randomInnerCoordinate(),
    };

    if (isSeaCoordinate(point.x, point.y)) continue;

    const tooClose = usedPoints.some((usedPoint) => {
      return getDistance(point.x, point.y, usedPoint.x, usedPoint.y) < minDistance;
    });

    if (!tooClose) return point;
  }

  return {
    x: randomInnerCoordinate(),
    y: randomInnerCoordinate(),
  };
}

// V68：70×70マップに合わせて、道路を縦横それぞれ4本へ増加。
// 旧仕様は実質「縦2本・横2本」だったため、縦横各2本ずつ増やす。
const roadLineCount = mapSize <= 15 ? 2 : mapSize <= 30 ? 3 : 4;
function createRoadLines(count) {
  const lines = [];
  for (let i = 1; i <= count; i++) {
    const base = Math.round((mapSize * i) / (count + 1));
    const jitter = mapSize <= 15 ? 0 : randomInt(-2, 2);
    lines.push(Math.max(2, Math.min(mapSize - 3, base + jitter)));
  }
  return Array.from(new Set(lines)).sort((a, b) => a - b);
}
const verticalRoadXs = createRoadLines(roadLineCount);
const horizontalRoadYs = createRoadLines(roadLineCount);

const firstRailVertical = seaSide === 0 || seaSide === 1;

// 1本目：海と平行に走るメイン線路。
// 海が左右にある時は縦線路、海が上下にある時は横線路にする。
const mainRailX = firstRailVertical
  ? seaSide === 1
    ? verticalRoadXs[verticalRoadXs.length - 1]
    : verticalRoadXs[0]
  : null;

const mainRailY = firstRailVertical
  ? null
  : seaSide === 3
    ? horizontalRoadYs[horizontalRoadYs.length - 1]
    : horizontalRoadYs[0];

// 2本目：1本目と交差する線路。
// 海に向かう側は海へ突き抜けさせず、海から約5マス手前で止めて終端駅を置く。
const secondRailVertical = !firstRailVertical;
const railCoordinateMin = Math.max(2, Math.floor(mapSize * 0.25));
const railCoordinateMax = Math.max(railCoordinateMin, mapSize - 3);
const secondRailX = secondRailVertical
  ? randomInt(railCoordinateMin, railCoordinateMax)
  : null;
const secondRailY = secondRailVertical
  ? null
  : randomInt(railCoordinateMin, railCoordinateMax);

const coastRailEndX = !hasSea
  ? (secondRailVertical ? null : mapSize - 3)
  : seaSide === 0
    ? Math.max(2, seaStart - 5)
    : seaSide === 1
      ? Math.min(mapSize - 3, mapSize - seaStart + 5)
      : null;

const coastRailEndY = !hasSea
  ? (secondRailVertical ? mapSize - 3 : null)
  : seaSide === 2
    ? Math.max(2, seaStart - 5)
    : seaSide === 3
      ? Math.min(mapSize - 3, mapSize - seaStart + 5)
      : null;

const railIntersection = firstRailVertical
  ? { x: mainRailX, y: secondRailY }
  : { x: secondRailX, y: mainRailY };

const coastalStation = firstRailVertical
  ? { x: coastRailEndX, y: secondRailY }
  : { x: secondRailX, y: coastRailEndY };

const stationPositions = [
  railIntersection,
  coastalStation,
];

const stationX = railIntersection.x;
const stationY = railIntersection.y;

function isMainRailCoordinate(x, y) {
  if (firstRailVertical) {
    return x === mainRailX && !isSeaCoordinate(x, y);
  }

  return y === mainRailY && !isSeaCoordinate(x, y);
}

function isSecondRailCoordinate(x, y) {
  if (secondRailVertical) {
    if (x !== secondRailX) return false;
    if (seaSide === 2) return y <= coastRailEndY && !isSeaCoordinate(x, y);
    if (seaSide === 3) return y >= coastRailEndY && !isSeaCoordinate(x, y);
    return !isSeaCoordinate(x, y);
  }

  if (y !== secondRailY) return false;
  if (seaSide === 0) return x <= coastRailEndX && !isSeaCoordinate(x, y);
  if (seaSide === 1) return x >= coastRailEndX && !isSeaCoordinate(x, y);
  return !isSeaCoordinate(x, y);
}

function isRailCoordinate(x, y) {
  return isMainRailCoordinate(x, y) || isSecondRailCoordinate(x, y);
}

const riverAnchor = hasSea ? randomInt(innerMin, innerMax) : 0;
const riverDelta = hasSea ? randomInt(-Math.max(3, Math.floor(mapSize / 4)), Math.max(3, Math.floor(mapSize / 4))) : 0;

function getRiverCenterByX(x) {
  const inlandStartX = seaSide === 0 ? 2 : seaSide === 1 ? mapSize - 3 : null;
  const coastEndX = seaSide === 0
    ? Math.max(4, seaStart - 1)
    : seaSide === 1
      ? Math.min(mapSize - 5, mapSize - seaStart + 1)
      : null;

  if (inlandStartX === null || coastEndX === null) return null;
  const progress = Math.max(0, Math.min(1, Math.abs(x - inlandStartX) / Math.max(1, Math.abs(coastEndX - inlandStartX))));
  return Math.round(riverAnchor + riverDelta * progress + Math.sin(x * 0.35) * 1.5);
}

function getRiverCenterByY(y) {
  const inlandStartY = seaSide === 2 ? 2 : seaSide === 3 ? mapSize - 3 : null;
  const coastEndY = seaSide === 2
    ? Math.max(4, seaStart - 1)
    : seaSide === 3
      ? Math.min(mapSize - 5, mapSize - seaStart + 1)
      : null;

  if (inlandStartY === null || coastEndY === null) return null;
  const progress = Math.max(0, Math.min(1, Math.abs(y - inlandStartY) / Math.max(1, Math.abs(coastEndY - inlandStartY))));
  return Math.round(riverAnchor + riverDelta * progress + Math.sin(y * 0.35) * 1.5);
}

function isRiverCoordinate(x, y) {
  if (!hasSea) return false;
  if (isSeaCoordinate(x, y)) return false;

  if (seaSide === 0 || seaSide === 1) {
    const centerY = getRiverCenterByX(x);
    if (centerY === null) return false;
    const coastEndX = seaSide === 0 ? Math.max(4, seaStart - 1) : Math.min(mapSize - 5, mapSize - seaStart + 1);
    const inRiverLength = seaSide === 0 ? x <= coastEndX : x >= coastEndX;
    return inRiverLength && Math.abs(y - centerY) <= 0;
  }

  const centerX = getRiverCenterByY(y);
  if (centerX === null) return false;
  const coastEndY = seaSide === 2 ? Math.max(4, seaStart - 1) : Math.min(mapSize - 5, mapSize - seaStart + 1);
  const inRiverLength = seaSide === 2 ? y <= coastEndY : y >= coastEndY;
  return inRiverLength && Math.abs(x - centerX) <= 0;
}

function isRoadCoordinate(x, y) {
  return verticalRoadXs.includes(x) || horizontalRoadYs.includes(y);
}

function isReservedFacilityCoordinate(x, y) {
  if (isSeaCoordinate(x, y)) return true;
  if (isRiverCoordinate(x, y)) return true;
  if (isRoadCoordinate(x, y)) return true;
  if (isRailCoordinate(x, y)) return true;
  if (stationPositions.some((station) => station.x === x && station.y === y)) return true;

  return false;
}

function createFacilityPoint(minDistance, usedPoints = []) {
  for (let attempt = 0; attempt < 400; attempt++) {
    const point = {
      x: randomInnerCoordinate(),
      y: randomInnerCoordinate(),
    };

    if (isReservedFacilityCoordinate(point.x, point.y)) continue;

    const tooClose = usedPoints.some((usedPoint) => {
      return getDistance(point.x, point.y, usedPoint.x, usedPoint.y) < minDistance;
    });

    if (!tooClose) return point;
  }

  for (let y = 5; y < mapSize - 5; y++) {
    for (let x = 5; x < mapSize - 5; x++) {
      if (isReservedFacilityCoordinate(x, y)) continue;

      const tooClose = usedPoints.some((usedPoint) => {
        return getDistance(x, y, usedPoint.x, usedPoint.y) < minDistance;
      });

      if (!tooClose) return { x, y };
    }
  }

  return { x: 5, y: 5 };
}

function getSchoolBlockTiles(topLeft) {
  return [
    { x: topLeft.x, y: topLeft.y },
    { x: topLeft.x + 1, y: topLeft.y },
    { x: topLeft.x, y: topLeft.y + 1 },
    { x: topLeft.x + 1, y: topLeft.y + 1 },
  ];
}

function canPlaceSchoolBlock(topLeft, usedPoints = [], minDistance = 8) {
  const blockTiles = getSchoolBlockTiles(topLeft);

  if (blockTiles.some((point) => point.x < 0 || point.x >= mapSize || point.y < 0 || point.y >= mapSize)) {
    return false;
  }

  if (blockTiles.some((point) => isReservedFacilityCoordinate(point.x, point.y))) {
    return false;
  }

  const tooClose = usedPoints.some((usedPoint) => {
    return blockTiles.some((point) => getDistance(point.x, point.y, usedPoint.x, usedPoint.y) < minDistance);
  });

  return !tooClose;
}

function createSchoolBlockPoint(minDistance, usedPoints = []) {
  for (let attempt = 0; attempt < 600; attempt++) {
    const point = {
      x: randomInt(innerMin, Math.max(innerMin, innerMax - 1)),
      y: randomInt(innerMin, Math.max(innerMin, innerMax - 1)),
    };

    if (canPlaceSchoolBlock(point, usedPoints, minDistance)) return point;
  }

  for (let y = 5; y < mapSize - 6; y++) {
    for (let x = 5; x < mapSize - 6; x++) {
      const point = { x, y };
      if (canPlaceSchoolBlock(point, usedPoints, minDistance)) return point;
    }
  }

  return { x: 5, y: 5 };
}

// v79方針：学校は1マスでは小さすぎるため、2×2の4マス施設として配置する。
// ユーザー指示により、学校4マスのどのマスも海・川・道路・線路・駅に重ならないようにしている。
// 工場も従来通り、海・川・道路・線路・駅・学校に重ならない場所へ先に確定する。
const schoolCount = targetSchoolCount;
const schoolBlocks = [];
const schoolPositions = [];
for (let i = 0; i < schoolCount; i++) {
  const schoolTopLeft = createSchoolBlockPoint(mapSize <= 15 ? 4 : 8, schoolPositions);
  const schoolTiles = getSchoolBlockTiles(schoolTopLeft);
  schoolBlocks.push({ topLeft: schoolTopLeft, tiles: schoolTiles });
  schoolPositions.push(...schoolTiles);
}

const schoolX = schoolPositions[0]?.x ?? 5;
const schoolY = schoolPositions[0]?.y ?? 5;

const factoryPoint = hasFactory ? createFacilityPoint(mapSize <= 30 ? 7 : 10, [...stationPositions, ...schoolPositions]) : null;
const factoryX = factoryPoint?.x ?? null;
const factoryY = factoryPoint?.y ?? null;

  const tiles = [];

  for (let y = 0; y < mapSize; y++) {
    for (let x = 0; x < mapSize; x++) {
     let terrain = TERRAIN.PLAIN;

// 山
if (
  (x < randomInt(2, 5) && y < randomInt(2, 8)) ||
  (mapSize >= 50 && x > mapSize - 20 && y < 8 && Math.random() < 0.7)
) {
  terrain = TERRAIN.MOUNTAIN;
}

// 川
if (isRiverCoordinate(x, y)) {
  terrain = TERRAIN.RIVER;
}

// 海
if (isSeaCoordinate(x, y)) {
  terrain = TERRAIN.SEA;
}

let feature = FEATURE.NONE;

// 道路
if (
  verticalRoadXs.includes(x) ||
  horizontalRoadYs.includes(y)
) {
  feature = FEATURE.ROAD;
}

// 線路
let rail = isRailCoordinate(x, y);

// 駅
if (stationPositions.some((station) => station.x === x && station.y === y)) {
  feature = FEATURE.STATION;
  rail = true;
}

// 学校
if (schoolPositions.some((school) => school.x === x && school.y === y)) {
  terrain = TERRAIN.PLAIN;
  feature = FEATURE.SCHOOL;
  rail = false;
}

// 工場
if (factoryX !== null && factoryY !== null && x === factoryX && y === factoryY) {
  terrain = TERRAIN.PLAIN;
  feature = FEATURE.FACTORY;
  rail = false;
}
// 海・川・山には道路や線路などを置かない
// 海と山だけは通れない
if (
  terrain === TERRAIN.MOUNTAIN ||
  terrain === TERRAIN.SEA
) {
  feature = FEATURE.NONE;
  rail = false;
}
      const landPrice = calculateLandPrice(
  x,
  y,
  terrain,
  feature,
  stationPositions,
  null,
  schoolPositions,
  null,
  factoryX,
  factoryY
);
      const zone = getZone(
  x,
  y,
  stationPositions,
  null,
  schoolPositions,
  null,
  factoryX,
  factoryY
);
      let owner = OWNER.OTHER;
      let building = null;
      let rooms = [];
      let age = 0;
　　　　let condition = 100;
      let buildingMainId = null;

      if (terrain !== TERRAIN.PLAIN || feature !== FEATURE.NONE) {
        owner = OWNER.PUBLIC;
      } else {
        const stationDistance = getNearestPointDistance(x, y, stationPositions, stationX, stationY);
        const schoolDistance = getNearestPointDistance(x, y, schoolPositions, schoolX, schoolY);

        if (stationDistance < 6 && Math.random() < 0.22) {
  building = Math.random() < 0.7 ? "house_2f" : "apt_2f_single";
  rooms = createRooms(building, 70, 0);
  age = randomInt(1, 25);
  condition = Math.max(40, 100 - age * randomInt(1, 3));
}

        if (!building && schoolDistance < 5 && Math.random() < 0.15) {
  building = "house_2f";
  rooms = createRooms(building, 75, 0);
  age = randomInt(1, 25);
  condition = Math.max(40, 100 - age * randomInt(1, 3));
}

        if (!building && Math.random() < 0.24) {
          owner = OWNER.SALE;
        }
      }

      if (building === "hq_apartment" && feature !== FEATURE.HQ) {
        building = null;
        rooms = [];
        buildingMainId = null;
      }

      tiles.push({
        id: y * mapSize + x,
        x,
        y,
        terrain,
        feature,
rail,
zone,
owner,
building,
        buildingMainId,
rooms,
age,
condition,
vacancyMonths: 0,
recoveryMode: false,
landPrice,
      });
    }
  }

function getRivalOfficeCandidates(minDistanceFromPlaced = 0, placedRivalOffices = [], requireRoadOrRail = true) {
  return tiles.filter((tile) => {
    if (tile.terrain !== TERRAIN.PLAIN) return false;
    if (tile.feature !== FEATURE.NONE) return false;
    // ライバル本社は道路・線路「沿い」には置けるが、道路上・線路上には置けない。
    if (tile.rail === true) return false;
    if (tile.building || tile.buildingMainId) return false;
    if (tile.owner !== OWNER.SALE) return false;
    if (requireRoadOrRail && !isTileNearRoadOrRail(tile, tiles)) return false;

    return placedRivalOffices.every((placedTile) => {
      return getDistance(tile.x, tile.y, placedTile.x, placedTile.y) >= minDistanceFromPlaced;
    });
  });
}

const placedRivalOffices = [];
const initialRivalCompanyIds = mapSize <= 15
  ? ["A"]
  : mapSize <= 30
    ? ["A", "B"]
    : ["A", "B", "C"];
const initialRivalCompanyNames = pickRandomRivalCompanyNames(initialRivalCompanyIds.length);
initialRivalCompanyIds.forEach((companyId, index) => {
  const company = getRivalCompany(companyId);
  const companyName = initialRivalCompanyNames[index] ?? company.name;
  const strictCandidates = getRivalOfficeCandidates(15, placedRivalOffices, true);
  const looseDistanceCandidates = getRivalOfficeCandidates(10, placedRivalOffices, true);
  const fallbackCandidates = getRivalOfficeCandidates(15, placedRivalOffices, false);
  const candidatePool = strictCandidates.length > 0
    ? strictCandidates
    : looseDistanceCandidates.length > 0
      ? looseDistanceCandidates
      : fallbackCandidates;

  const rivalOfficeTile = candidatePool.length > 0
    ? candidatePool[randomInt(0, candidatePool.length - 1)]
    : null;

  if (!rivalOfficeTile) return;

  const rivalEmployee = {
    ...pickRivalInitialEmployee("rookie", placedRivalOffices.flatMap((office) => (office.rivalEmployees ?? []).map((employee) => employee.sourceEmployeeId ?? employee.originalEmployeeId ?? employee.id))),
    officeId: `rival_${company.id}_hq`,
  };
  rivalOfficeTile.owner = OWNER.RIVAL;
  rivalOfficeTile.feature = FEATURE.HQ;
  rivalOfficeTile.building = null;
  rivalOfficeTile.rivalCompanyId = company.id;
  rivalOfficeTile.rivalCompanyName = companyName;
  rivalOfficeTile.rivalOfficeName = `${companyName} 本社`;
  rivalOfficeTile.rivalEmployees = [rivalEmployee];
  rivalOfficeTile.rivalMoney = company.initialMoney;
  placedRivalOffices.push(rivalOfficeTile);
});

return {
  tiles: recalculateTileZonesByFacilities(tiles),
  stationX,
  stationY,
  stationPositions,
  schoolX,
  schoolY,
  schoolPositions,
  factoryX,
  factoryY,
};
}

function getTerrainName(terrain) {
  if (terrain === TERRAIN.PLAIN) return "平地";
  if (terrain === TERRAIN.MOUNTAIN) return "山";
  if (terrain === TERRAIN.RIVER) return "川";
  if (terrain === TERRAIN.SEA) return "海";
  return "不明";
}

function getFeatureName(feature) {
  if (feature === FEATURE.ROAD) return "道路";
  if (feature === FEATURE.STATION) return "駅";
  if (feature === FEATURE.SCHOOL) return "学校";
  if (feature === FEATURE.FACTORY) return "工場";
  if (feature === FEATURE.HQ) return "本社";
  if (feature === FEATURE.BRANCH) return "支店";
  return "なし";
}
function getZoneName(zone) {
  if (zone === ZONE.RESIDENTIAL) return "住宅地域";
  if (zone === ZONE.COMMERCIAL) return "商業地域";
  if (zone === ZONE.INDUSTRIAL) return "工業地域";
  return "一般地域";
}

function getOwnerName(owner) {
  if (owner === OWNER.PLAYER) return "自分";
  if (owner === OWNER.SALE) return "売り物件";
  if (owner === OWNER.OTHER) return "他人";
  if (owner === OWNER.PUBLIC) return "公共・自然";
  if (owner === OWNER.RIVAL) return "ライバル企業";

  return "不明";
}

function getGameOverAkariComment(finalMoney = 0) {
  const deficit = Math.abs(Math.min(0, Math.round(Number(finalMoney) || 0)));
  if (deficit >= 10000) {
    return `社長……ここまで大きく資金が割り込んでしまいました。通常なら経営終了ですが、メダル${GAME_OVER_RESCUE_MEDAL_COST}枚で再建支援を受けることもできます。`;
  }
  if (deficit >= 3000) {
    return `資金繰りが詰まってしまいました……。残念ですが、メダル${GAME_OVER_RESCUE_MEDAL_COST}枚で一度だけ立て直す道もあります。`;
  }
  return `所持金がマイナスになってしまいました……。残念です。ただ、メダル${GAME_OVER_RESCUE_MEDAL_COST}枚で再建支援を受けることができます。`;
}

function getGameDate(month) {
  const startMonth = 4;
  const totalMonths = startMonth + month - 2;

  const year = Math.floor(totalMonths / 12) + 1;
  const displayMonth = (totalMonths % 12) + 1;

  return {
    year,
    month: displayMonth,
    label: `${year}年目${displayMonth}月`,
  };
}

function getSeasonDemandBonus(gameMonth, buildingKey) {
  const building = BUILDINGS[buildingKey];
  if (!building) return 0;

  if (
    building.category === "住宅" ||
    building.category === "住宅" ||
    building.category === "住宅"
  ) {
    if (gameMonth === 2) return 5;
    if (gameMonth === 3 || gameMonth === 4) return 12;
    if (gameMonth === 9 || gameMonth === 10) return 4;
    if (gameMonth === 11 || gameMonth === 12 || gameMonth === 1) return -6;
  }

  if (building.category === "商業") {
    if (gameMonth === 12) return 8;
    if (gameMonth === 3 || gameMonth === 4) return 5;
    if (gameMonth === 1 || gameMonth === 2) return -3;
  }

  return 0;
}
function calculateBuildingValue(tile) {
  if (!tile || !tile.building) return 0;

  const building = BUILDINGS[tile.building];
  if (!building) return 0;

  const age = tile.age ?? 0;
  const condition = tile.condition ?? 100;

  const ageRate = Math.max(0.2, 1 - age / building.lifeYears);
  const conditionRate = condition / 100;

  return Math.round(building.cost * ageRate * conditionRate);
}
function calculateMonthlyExpenses(tile) {
  const details = calculateMonthlyExpenseDetails(tile);
  return details.total;
}

function calculateMonthlyExpenseDetails(tile) {
  if (!tile?.building) {
    return {
      managementFee: 0,
      insurance: 0,
      repairReserve: 0,
      propertyTaxMonthlyReference: 0,
      total: 0,
    };
  }

  const building = BUILDINGS[tile.building];
  if (!building) {
    return {
      managementFee: 0,
      insurance: 0,
      repairReserve: 0,
      propertyTaxMonthlyReference: 0,
      total: 0,
    };
  }

  const occupiedRent = (tile.rooms ?? []).reduce((sum, room) => {
    return sum + (room.occupied ? room.rent : 0);
  }, 0);

  const managementFee = occupiedRent * 0.05;
  const insurance = building.cost * 0.002 / 12;
  const repairReserve = building.cost * 0.006 / 12;
  const propertyTaxMonthlyReference = tile.owner === OWNER.PLAYER
    ? calculateYearlyPropertyTax(tile) / 12
    : 0;

  return {
    managementFee: Math.round(managementFee),
    insurance: Math.round(insurance),
    repairReserve: Math.round(repairReserve),
    propertyTaxMonthlyReference: Math.round(propertyTaxMonthlyReference),
    total: Math.round(managementFee + insurance + repairReserve),
  };
}

function calculateYearlyPropertyTax(tile) {
  if (!tile || tile.owner !== OWNER.PLAYER) return 0;

  const landTax = tile.landPrice * 0.014;

  const buildingTax =
    tile.building && !tile.buildingMainId
      ? calculateBuildingValue(tile) * 0.014
      : 0;

  return Math.round(landTax + buildingTax);
}

function calculateCompanyYearlyPropertyTax(tile) {
  if (!tile) return 0;

  const landTax = (tile.landPrice ?? 0) * 0.014;

  const buildingTax =
    tile.building && !tile.buildingMainId
      ? calculateBuildingValue(tile) * 0.014
      : 0;

  return Math.round(landTax + buildingTax);
}
function getOldBuildingActionChance(tile) {
  if (!tile?.building) return null;

  const building = BUILDINGS[tile.building];
  const age = tile.age ?? 0;
  const condition = tile.condition ?? 100;
  const life = building.lifeYears;

  if (age < life * 0.9) return null;

  let sellChance = 0.002;
  let demolishChance = 0.001;

  if (age >= life) {
    sellChance += 0.006;
    demolishChance += 0.004;
  }

  if (age >= life * 1.3) {
    sellChance += 0.008;
    demolishChance += 0.008;
  }

  if (condition < 50) {
    sellChance += 0.006;
    demolishChance += 0.006;
  }

  return {
    sellChance,
    demolishChance,
  };
}

function loadSavedGameSafely() {
  if (typeof window === "undefined") return null;

  const currentSlot = getCurrentSaveSlot();
  const currentSlotSave = readSaveSlot(currentSlot);
  if (currentSlotSave) return currentSlotSave;

  const firstSlotSave = readSaveSlot(DEFAULT_SAVE_SLOT);
  if (firstSlotSave) return firstSlotSave;

  try {
    const rawSaveData = window.localStorage.getItem("realEstateGameSave");
    if (!rawSaveData) return null;

    const parsedSaveData = JSON.parse(rawSaveData);
    if (!parsedSaveData || typeof parsedSaveData !== "object") return null;
    if (!Array.isArray(parsedSaveData.tiles)) return null;

    return parsedSaveData;
  } catch (error) {
    console.warn("Save data could not be loaded. Starting with a safe new map.", error);
    return null;
  }
}

