useEffect(() => {
  // v193: 保管庫から持ち込んだ創業メンバーは、前の会社の行動中状態を引き継がない。
  // 既にv192で開始済みのデータでも、創業メンバー扱いの社員を本社配属・行動可能に補正する。
  const hasPlayerOfficeForFounderFix = hqPlaced || tiles.some((tile) => tile?.owner === OWNER.PLAYER && (tile?.feature === FEATURE.HQ || tile?.feature === FEATURE.BRANCH));
  if (!hasPlayerOfficeForFounderFix) return;

  setEmployees((currentEmployees) => {
    let changed = false;

    const nextEmployees = currentEmployees
      .filter((employee) => employee.id !== 0)
      .map((employee) => {
        const shouldFixFounder =
          employee.founderCarryOver === true ||
          (
            isFreeModeKey(currentGameMode) &&
            employee.officeId === "hq" &&
            employee.busyUntilMonth &&
            employee.busyUntilMonth > month &&
            month <= 6
          );

        if (!shouldFixFounder) return employee;

        changed = true;
        const remoteBranchOfficeId = isRemoteBranchStartMode(currentGameMode)
          ? (tiles.find((tile) => tile?.owner === OWNER.PLAYER && tile?.feature === FEATURE.BRANCH && tile?.officeId)?.officeId ?? employee.officeId ?? "waiting")
          : "hq";
        return normalizeEmployeeGrowthBase({
          ...employee,
          officeId: remoteBranchOfficeId,
          busyUntilMonth: null,
          busyActionName: null,
          founderCarryOver: true,
          currentAssignment: createEmployeeAssignmentFromGame({ ...employee, officeId: remoteBranchOfficeId }, {
            currentGameMode,
            freeMapKey: isFreeModeKey(currentGameMode) ? normalizeFreeModeKey(currentGameMode) : null,
            activeSaveSlot: savedGame?.activeSaveSlot ?? getCurrentSaveSlot(),
          }),
        });
      });

    return changed ? nextEmployees : currentEmployees;
  });
}, [hqPlaced, currentGameMode, tiles, month, savedGame]);

useEffect(() => {
  const hasPlayerHQ = tiles.some((tile) => {
    return tile.owner === OWNER.PLAYER && tile.feature === FEATURE.HQ;
  });

  if (hasPlayerHQ && !hqPlaced) {
    setHqPlaced(true);
    setActionPoints((current) => Math.max(current, 1));
    setActivePanel((currentPanel) => currentPanel === "hq" ? "home" : currentPanel);
  }
}, [tiles, hqPlaced]);

// v310.31: 岐阜以外の支店スタートマップでは、本社未設置フェーズを
// 必ず3億円以上へ補正する。前章の赤字を持ち込ませず、初回支店設置まで進められるようにする。
useEffect(() => {
  // v310.35: officeTiles の useMemo 定義より前で officeTiles を参照すると
  // TDZ エラーで白画面になるため、ここでは tiles から直接判定する。
  const hasAnyPlayerOffice = tiles.some((tile) => {
    return tile.owner === OWNER.PLAYER && (tile.feature === FEATURE.HQ || tile.feature === FEATURE.BRANCH);
  });
  if (!isRemoteBranchStartMode(currentGameMode) || hasAnyPlayerOffice) return;

  setMoney((currentMoney) => {
    const safeMoney = Math.round(Number(currentMoney) || 0);
    return safeMoney < 30000 ? 30000 : safeMoney;
  });

  setLoans((currentLoans) => (Array.isArray(currentLoans) && currentLoans.length > 0 ? [] : currentLoans));
  setPendingLoanApplications((currentApplications) => (Array.isArray(currentApplications) && currentApplications.length > 0 ? [] : currentApplications));
}, [currentGameMode, tiles]);

useEffect(() => {
  if (currentGameMode !== "story" || !tutorialStep) return;

  const oldHouseTile = tiles.find((tile) => tile.tutorialTag === "old_house");
  const apartmentLandTile = tiles.find((tile) => tile.tutorialTag === "apartment_land");

  if (
    tutorialStep === STORY_TUTORIAL_STEPS.BUY_OLD_HOUSE &&
    oldHouseTile?.owner === OWNER.PLAYER
  ) {
    setTutorialStep(STORY_TUTORIAL_STEPS.REPAIR_OLD_HOUSE);
    setSelectedId(oldHouseTile.id);
    setActivePanel("land");
    setStoryEvent(STORY_TUTORIAL_EVENTS.PURCHASED_OLD_HOUSE);
    setLog("戸建を購入できました。次は修繕で建物状態を70以上まで回復させましょう。");
    return;
  }

  if (
    tutorialStep === STORY_TUTORIAL_STEPS.REPAIR_OLD_HOUSE &&
    oldHouseTile?.owner === OWNER.PLAYER &&
    Number(oldHouseTile?.condition ?? 0) >= 70
  ) {
    forceStoryAkariLevel(2, "修繕をやり遂げ、物件再生の基本を身につけました。");
    setTutorialStep(STORY_TUTORIAL_STEPS.BUY_APARTMENT_LAND);
    if (apartmentLandTile) setSelectedId(apartmentLandTile.id);
    setActivePanel("land");
    setStoryEvent(STORY_TUTORIAL_EVENTS.REPAIRED_OLD_HOUSE);
    setLog("見違えるほど綺麗になりました。これなら借りたい人も見つかりそうです。次は指定された空き地を購入しましょう。");
    return;
  }

  if (
    tutorialStep === STORY_TUTORIAL_STEPS.BUY_APARTMENT_LAND &&
    apartmentLandTile?.owner === OWNER.PLAYER
  ) {
    setTutorialStep(STORY_TUTORIAL_STEPS.BUILD_APARTMENT);
    setSelectedId(apartmentLandTile.id);
    setActivePanel("build");
    setStoryEvent(STORY_TUTORIAL_EVENTS.PURCHASED_APARTMENT_LAND);
    setLog("空き地を購入できました。次はこの土地に平屋戸建を建ててみましょう。");
    return;
  }

  const hasTutorialApartment = tiles.some((tile) => {
    return tile.owner === OWNER.PLAYER &&
      tile.building === "house_1f" &&
      tile.tutorialTag === "apartment_land" &&
      tile.buildingStatus === "active";
  });

  if (
    tutorialStep === STORY_TUTORIAL_STEPS.BUILD_APARTMENT &&
    hasTutorialApartment
  ) {
    forceStoryAkariLevel(3, "新築賃貸の基本を身につけました。");
    setTutorialStep(STORY_TUTORIAL_STEPS.COMPLETE);
    setActivePanel("home");
    setStoryEvent(STORY_TUTORIAL_EVENTS.BUILT_APARTMENT);
    setLog("建物って自分で建てられるんですね。1-1章の基本操作は完了です。");
    writeAccountData(mergeAccountDataWithGame(readAccountData(), {
      playerRank,
      playerExp,
      employees: employeesRef.current.length > 0 ? employeesRef.current : employees,
      employeeStorage,
      currentGameMode,
      freeMapKey: isFreeModeKey(currentGameMode) ? normalizeFreeModeKey(currentGameMode) : null,
      activeSaveSlot: savedGame?.activeSaveSlot ?? getCurrentSaveSlot(),
      hasClearedGifuChapter,
      hasClearedNagoyaChapter,
      hasClearedKyotoChapter,
      hasClearedOsakaChapter,
      hasClearedTokyoChapter,
      hasCompletedKyotoTourismTutorial,
      hasCompletedOsakaIndustrialTutorial,
      rookieEmployeeTickets,
      employeeTickets,
      premiumEmployeeTickets,
    }));
    setHomeAccountRefreshKey((current) => current + 1);
  }
}, [currentGameMode, tutorialStep, tiles, playerRank, playerExp, employees, employeeStorage, hasClearedNagoyaChapter, hasClearedKyotoChapter, hasCompletedKyotoTourismTutorial, rookieEmployeeTickets, employeeTickets, premiumEmployeeTickets]);



