function getSelectedTileHeaderIcon(tile = selectedTile, mainTile = selectedMainTile, buildingInfo = selectedBuilding) {
  if (!tile) return "🗺️";
  if ((mainTile?.buildRemaining ?? 0) > 0) return "🚧";
  if (tile.feature === FEATURE.HQ) return "🏢";
  if (tile.feature === FEATURE.BRANCH) return "🏬";
  if (tile.feature === FEATURE.STATION) return "🚉";
  if (tile.feature === FEATURE.SCHOOL) return "🏫";
  if (tile.feature === FEATURE.ROAD) return "🛣️";
  if (buildingInfo) {
    if (buildingInfo.subCategory === "戸建") return "🏠";
    if (buildingInfo.subCategory === "アパート") return "🏘️";
    if (buildingInfo.subCategory === "マンション") return "🏢";
    if (buildingInfo.category === "商業") return "🏪";
    if (buildingInfo.category === "工業") return "🏭";
    if (buildingInfo.category === "観光") return "♨️";
    return "🏠";
  }
  if (tile.owner === OWNER.SALE) return "🏷️";
  if (tile.owner === OWNER.PLAYER) return "📍";
  return "🗺️";
}

function getSelectedBuildProgressMeta(tile = selectedMainTile, buildingInfo = selectedBuilding) {
  const remaining = Math.max(0, Math.round(Number(tile?.buildRemaining) || 0));
  if (!tile || remaining <= 0) return null;

  const total = Math.max(
    1,
    Math.round(Number(tile.buildActualMonths || tile.buildStandardMonths || buildingInfo?.buildMonths || remaining) || remaining)
  );
  const completed = Math.max(0, total - remaining);
  const progress = Math.max(0, Math.min(100, Math.round((completed / total) * 100)));

  return { remaining, total, progress };
}

function getFloatingPanelTitle(panelName = activePanel) {
  if (panelName === "hq") return "本社設置（本社タイプを選択）";

  if (panelName === "land") {
    const progressMeta = getSelectedBuildProgressMeta();
    const baseTitle = !selectedTile
      ? "土地情報"
      : selectedBuilding
        ? selectedBuilding.name
        : selectedTile.feature === FEATURE.HQ
          ? "本社"
          : selectedTile.feature === FEATURE.BRANCH
            ? getBranchDisplayName(selectedTile)
            : "土地情報";

    return (
      <span className="floating-land-title-v2187">
        <span className="floating-land-title-main-v2187">
          <span className="floating-land-title-icon-v2187">{getSelectedTileHeaderIcon()}</span>
          <span className="floating-land-title-text-v2187">{baseTitle}</span>
        </span>
        {progressMeta && (
          <span className="floating-land-build-progress-v2187" title={`工事進捗 ${progressMeta.progress}% / 残り${progressMeta.remaining}ヶ月`}>
            <span className="floating-land-build-label-v2187">残{progressMeta.remaining}ヶ月</span>
            <span className="floating-land-build-meter-v2187">
              <span style={{ width: `${progressMeta.progress}%` }} />
            </span>
          </span>
        )}
      </span>
    );
  }

  if (panelName === "build") {
    if (!selectedBuildCategory) return "建設メニュー";
    if (selectedBuildCategory === "住宅" && selectedHousingType) return `建設：${selectedHousingType}`;
    return `建設：${selectedBuildCategory}`;
  }

  if (panelName === "employee") return "社員配置";
  if (panelName === "employeeRecruit") return "社員採用";
  if (panelName === "employeeLibrary") return "社員名簿";
  return "操作パネル";
}

function handleFloatingPanelPointerDown(event) {
  if (event.button !== undefined && event.button !== 0) return;
  if (event.target.closest?.("button, input, select, textarea, a, .floating-panel-resize-handle")) return;
  event.preventDefault();
  event.stopPropagation();

  floatingPanelDragRef.current = {
    pointerId: event.pointerId,
    startX: event.clientX,
    startY: event.clientY,
    panelX: floatingPanel.x,
    panelY: floatingPanel.y,
  };

  event.currentTarget.setPointerCapture?.(event.pointerId);
}

function handleFloatingPanelPointerMove(event) {
  const drag = floatingPanelDragRef.current;
  if (!drag || drag.pointerId !== event.pointerId) return;

  event.preventDefault();
  event.stopPropagation();

  const nextX = drag.panelX + event.clientX - drag.startX;
  const nextY = drag.panelY + event.clientY - drag.startY;
  const maxX = Math.max(0, window.innerWidth - 160);
  const maxY = Math.max(0, window.innerHeight - 120);

  setFloatingPanel((current) => ({
    ...current,
    x: Math.max(0, Math.min(maxX, nextX)),
    y: Math.max(0, Math.min(maxY, nextY)),
  }));
}

function handleFloatingPanelPointerUp(event) {
  const drag = floatingPanelDragRef.current;
  if (!drag || drag.pointerId !== event.pointerId) return;

  event.preventDefault();
  event.stopPropagation();
  floatingPanelDragRef.current = null;
  event.currentTarget.releasePointerCapture?.(event.pointerId);
}

function handleFloatingPanelResizePointerDown(event) {
  if (event.button !== undefined && event.button !== 0) return;
  event.preventDefault();
  event.stopPropagation();

  floatingPanelResizeRef.current = {
    pointerId: event.pointerId,
    startX: event.clientX,
    startY: event.clientY,
    panelWidth: floatingPanel.width,
    panelHeight: floatingPanel.height,
  };

  event.currentTarget.setPointerCapture?.(event.pointerId);
}

function handleFloatingPanelResizePointerMove(event) {
  const resize = floatingPanelResizeRef.current;
  if (!resize || resize.pointerId !== event.pointerId) return;

  event.preventDefault();
  event.stopPropagation();

  const minWidth = 280;
  const minHeight = 200;
  const maxWidth = Math.max(minWidth, window.innerWidth - floatingPanel.x - 12);
  const maxHeight = Math.max(minHeight, window.innerHeight - floatingPanel.y - 12);
  const nextWidth = resize.panelWidth + event.clientX - resize.startX;
  const nextHeight = resize.panelHeight + event.clientY - resize.startY;

  setFloatingPanel((current) => ({
    ...current,
    width: Math.max(minWidth, Math.min(maxWidth, nextWidth)),
    height: Math.max(minHeight, Math.min(maxHeight, nextHeight)),
  }));
}

function handleFloatingPanelResizePointerUp(event) {
  const resize = floatingPanelResizeRef.current;
  if (!resize || resize.pointerId !== event.pointerId) return;

  event.preventDefault();
  event.stopPropagation();
  floatingPanelResizeRef.current = null;
  event.currentTarget.releasePointerCapture?.(event.pointerId);
}

