function getRecruitEnvelopeType(rarity) {
  if (["SSR", "UR"].includes(rarity)) return "black";
  if (rarity === "SR") return "brown";
  return "white";
}

function getRecruitEnvelopeLabel(envelopeType) {
  if (envelopeType === "black") return "黒封筒";
  if (envelopeType === "brown") return "茶封筒";
  return "白封筒";
}

function getRecruitmentAnnouncementSignal(applicants = [], ticketType = "normal") {
  const rarityOrders = { N: 1, R: 2, HR: 3, SR: 4, SSR: 5, UR: 6 };
  const highestOrder = (Array.isArray(applicants) ? applicants : []).reduce((maxOrder, applicant) => {
    return Math.max(maxOrder, rarityOrders[applicant?.rarity] ?? 1);
  }, 1);
  const roll = Math.random() * 100;

  if (highestOrder >= 5) {
    if (roll < 24) return { key: "rainbow", icon: "🌈", label: "特別な気配", title: "応募書類到着！", description: "封筒がまばゆく輝いています。すごい履歴書が入っているかもしれません。" };
    if (roll < 58) return { key: "red", icon: "🔴", label: "かなり期待", title: "応募書類到着！", description: "封筒から強い光が漏れています。期待できそうです。" };
    if (roll < 82) return { key: "green", icon: "🟢", label: "少し期待", title: "応募書類到着！", description: "封筒がやわらかく光っています。良い出会いがありそうです。" };
    return { key: "blue", icon: "🔵", label: "通常", title: "応募書類到着！", description: "封筒が届きました。中身を確認してみましょう。" };
  }

  if (highestOrder >= 4) {
    if (roll < 42) return { key: "red", icon: "🔴", label: "かなり期待", title: "応募書類到着！", description: "封筒から強い光が漏れています。期待できそうです。" };
    if (roll < 76) return { key: "green", icon: "🟢", label: "少し期待", title: "応募書類到着！", description: "封筒がやわらかく光っています。良い出会いがありそうです。" };
    return { key: "blue", icon: "🔵", label: "通常", title: "応募書類到着！", description: "封筒が届きました。中身を確認してみましょう。" };
  }

  if (highestOrder >= 3) {
    if (roll < 48) return { key: "green", icon: "🟢", label: "少し期待", title: "応募書類到着！", description: "封筒がやわらかく光っています。良い出会いがありそうです。" };
    return { key: "blue", icon: "🔵", label: "通常", title: "応募書類到着！", description: "封筒が届きました。中身を確認してみましょう。" };
  }

  return { key: "blue", icon: "🔵", label: "通常", title: "応募書類到着！", description: "封筒が届きました。中身を確認してみましょう。" };
}

function getRecruitDeliveryPhaseText(step = "delivery") {
  if (step === "delivery") return { title: "応募書類配達中...", subtitle: "本社宛ての大封筒が近づいています。", icon: "📮" };
  if (step === "arrival") return { title: "応募書類到着！", subtitle: "封筒が届きました。光の色はあくまで期待演出です。", icon: "📬" };
  return { title: "応募書類到着！", subtitle: "封筒が届きました。光の色はあくまで期待演出です。", icon: "📬" };
}

function createRecruitmentApplicants(ticketType) {
  const isPremium = ticketType === "premium";
  const isRookie = ticketType === "rookie";
  const availableEmployees = EMPLOYEE_POOL.filter((employee) => {
    if (isPremium) return ["SR", "SSR", "UR"].includes(employee.rarity);
    if (isRookie) return ["N", "R", "HR", "SR", "SSR"].includes(employee.rarity);
    return true;
  });

  const recruitSkillEffects = getActiveEmployeeSkillEffectTotals(employees);
  const applicantCount = Math.min(5, EMPLOYEE_RECRUITMENT_ENVELOPE_COUNT + getRecruitApplicantBonus(recruitSkillEffects));
  const pickedEmployees = [];

  for (let i = 0; i < applicantCount; i++) {
    const pickedEmployee = pickRecruitEmployee(availableEmployees, pickedEmployees, ticketType);
    if (pickedEmployee) {
      pickedEmployees.push(pickedEmployee);
    }
  }

  return pickedEmployees.map((employee, index) => {
    const normalizedEmployee = normalizeEmployeeGrowthBase({
      ...employee,
      officeId: null,
    });
    const envelopeType = getRecruitEnvelopeType(normalizedEmployee.rarity);

    return {
      ...normalizedEmployee,
      envelopeId: `${ticketType}-${Date.now()}-${index}-${normalizedEmployee.id}`,
      envelopeType,
      opened: false,
    };
  });
}

function startEmployeeRecruitmentByTicket(ticketType) {
  if (!hqPlaced) {
    alert("先に本社を設置してください");
    return;
  }

  const isPremium = ticketType === "premium";
  const isRookie = ticketType === "rookie";

  if (isRookie && rookieEmployeeTickets < 1) {
    alert("社員採用チケットがありません。社員採用には社員採用チケット1枚が必要です。");
    return;
  }

  if (!isPremium && !isRookie && employeeTickets < 1) {
    alert("レア社員採用チケットがありません。レア社員採用にはレア社員採用チケット1枚が必要です。");
    return;
  }

  if (isPremium && premiumEmployeeTickets < 1) {
    alert("プレミア社員採用チケットがありません。プレミア社員採用にはプレミア社員採用チケット1枚が必要です。");
    return;
  }

  const applicants = createRecruitmentApplicants(ticketType);

  if (applicants.length === 0) {
    alert("応募者を生成できませんでした");
    return;
  }

  if (isPremium) {
    setPremiumEmployeeTickets(premiumEmployeeTickets - 1);
  } else if (isRookie) {
    setRookieEmployeeTickets(rookieEmployeeTickets - 1);
  } else {
    setEmployeeTickets(employeeTickets - 1);
  }

  const announcementSignal = getRecruitmentAnnouncementSignal(applicants, ticketType);

  setEmployeeCandidates([]);
  setEmployeeGachaResult(null);
  setEmployeeRecruitAnimationStep("delivery");
  setEmployeeRecruitmentOffer({
    ticketType,
    applicants,
    selectedEnvelopeId: null,
    source: "map",
    announcementSignal,
  });

  setLog(`${getTicketName(ticketType)}1枚を使い、履歴書が${applicants.length}通届きました。封筒を開封して1人を採用してください。`);
}

function openRecruitEnvelope(envelopeId) {
  setEmployeeRecruitmentOffer((currentOffer) => {
    if (!currentOffer) return currentOffer;

    return {
      ...currentOffer,
      selectedEnvelopeId: envelopeId,
      applicants: currentOffer.applicants.map((applicant) => {
        if (applicant.envelopeId !== envelopeId) return applicant;
        return {
          ...applicant,
          opened: true,
        };
      }),
    };
  });
}

function returnAfterEmployeeRecruitment() {
  const source = employeeRecruitmentOffer?.source === "home" ? "home" : "map";
  setTitleVaultDetailEmployee(null);
  setIsMapEmployeeMenuOpen(false);
  setIsMainMenuOpen(false);
  setIsMapInfoMenuOpen(false);

  if (source === "home") {
    setShowTitleScreen(true);
    setTitleModal("recruitHome");
    setEmployeeRecruitReturnPanel("home");
    return;
  }

  setShowTitleScreen(false);
  setTitleModal(null);
  setActivePanel("employeeRecruit");
  setEmployeeRecruitReturnPanel("employeeRecruit");
}

function cancelEmployeeRecruitmentOffer() {
  const ok = window.confirm(
    "今回届いた履歴書を閉じますか？\n\n採用チケットは使用済みのため戻りません。"
  );

  if (!ok) return;

  returnAfterEmployeeRecruitment();
  setEmployeeRecruitmentOffer(null);
  setEmployeeRecruitAnimationStep("ready");
  setLog("社員採用を終了しました。今回は採用を見送りました。");
}

function findOwnedEmployeeById(employeeId) {
  const assignedEmployee = employees.find((employee) => employee.id === employeeId);
  if (assignedEmployee) return { employee: assignedEmployee, location: "assigned" };

  const storedEmployee = employeeStorage.find((employee) => employee.id === employeeId);
  if (storedEmployee) return { employee: storedEmployee, location: "storage" };

  return null;
}

function awakenEmployee(employee) {
  const normalizedEmployee = normalizeEmployeeGrowthBase(employee);
  const currentAwakening = Math.max(0, Math.round(normalizedEmployee.awakening ?? 0));

  if (currentAwakening >= EMPLOYEE_AWAKENING_MAX) {
    const levelUpResult = applyEmployeeLevelUps(normalizedEmployee, 500);
    return {
      employee: levelUpResult.employee,
      wasMaxAwakening: true,
      statMessages: ["覚醒上限のため研修EXP+500"],
      beforeAwakening: currentAwakening,
      afterAwakening: currentAwakening,
    };
  }

  const statKeys = [
    { key: "leadership", label: "統率" },
    { key: "sales", label: "営業" },
    { key: "construction", label: "建築" },
    { key: "management", label: "管理" },
  ];
  const statMessages = [];
  let updatedEmployee = {
    ...normalizedEmployee,
    awakening: currentAwakening + 1,
  };

  statKeys.forEach((stat) => {
    const currentValue = updatedEmployee[stat.key] ?? 0;
    const increase = (currentAwakening + 1) * 5;
    updatedEmployee = {
      ...updatedEmployee,
      [stat.key]: currentValue + increase,
    };
    statMessages.push(`${stat.label}+${increase}`);
  });

  return {
    employee: updatedEmployee,
    wasMaxAwakening: false,
    statMessages,
    beforeAwakening: currentAwakening,
    afterAwakening: currentAwakening + 1,
  };
}

function confirmRecruitApplicant(applicant) {
  if (!employeeRecruitmentOffer) return;

  if (!applicant.opened) {
    alert("先に封筒を開封してください。");
    return;
  }

  const ownedEmployeeInfo = findOwnedEmployeeById(applicant.id);

  if (ownedEmployeeInfo) {
    const awakeningPreview = awakenEmployee(ownedEmployeeInfo.employee);
    const ok = window.confirm(
      `${applicant.name}はすでに在籍・保管中です。\n\n` +
        `同じ社員を採用扱いにして覚醒しますか？\n` +
        `覚醒: +${awakeningPreview.beforeAwakening} → +${awakeningPreview.afterAwakening}\n` +
        `${awakeningPreview.statMessages.join(" / ")}`
    );

    if (!ok) return;

    if (ownedEmployeeInfo.location === "assigned") {
      setEmployees((currentEmployees) => {
        return currentEmployees.map((employee) => {
          if (employee.id !== applicant.id) return employee;
          return awakeningPreview.employee;
        });
      });
    } else {
      setEmployeeStorage((currentStorage) => {
        return currentStorage.map((employee) => {
          if (employee.id !== applicant.id) return employee;
          return awakeningPreview.employee;
        });
      });
    }

    setEmployeeGachaResult({
      ...awakeningPreview.employee,
      awakened: true,
      source: employeeRecruitmentOffer?.source === "home" ? "home" : "map",
      beforeAwakening: awakeningPreview.beforeAwakening,
      afterAwakening: awakeningPreview.afterAwakening,
      awakeningMessages: awakeningPreview.statMessages,
      wasMaxAwakening: awakeningPreview.wasMaxAwakening,
    });
    returnAfterEmployeeRecruitment();
    setEmployeeRecruitmentOffer(null);
    setEmployeeRecruitAnimationStep("ready");
    setLog(
      `${applicant.name}がダブりました。覚醒+${awakeningPreview.afterAwakening}になりました。${awakeningPreview.statMessages.join(" / ")}`
    );
    return;
  }

  const ok = window.confirm(
    `${applicant.name}を採用しますか？\n\n` +
      `レアリティ: ${applicant.rarity}\n` +
      `統率: ${applicant.leadership}\n` +
      `営業: ${applicant.sales}\n` +
      `建築: ${applicant.construction}\n` +
      `管理: ${applicant.management}\n` +
      `特殊能力: ${getEmployeeSpecialText(applicant)}\n\n` +
      `残りの履歴書${Math.max(0, (employeeRecruitmentOffer?.applicants?.length ?? 1) - 1)}通とは縁がなかったことになります。`
  );

  if (!ok) return;

  const hiredEmployee = normalizeEmployeeGrowthBase({
    ...applicant,
    envelopeId: undefined,
    envelopeType: undefined,
    opened: undefined,
    officeId: null,
  });

  setEmployeeStorage([
    ...employeeStorage,
    hiredEmployee,
  ]);

  setEmployeeGachaResult({
    ...hiredEmployee,
    awakened: false,
    ticketType: employeeRecruitmentOffer.ticketType,
    source: employeeRecruitmentOffer?.source === "home" ? "home" : "map",
  });
  returnAfterEmployeeRecruitment();
  setEmployeeRecruitmentOffer(null);
  setEmployeeRecruitAnimationStep("ready");

  setLog(
    `${hiredEmployee.name}（${hiredEmployee.rarity}）を採用しました。社員保管庫に追加しました。配属する場合は社員配置から呼び出してください。現在の呼び出し枠:${employees.length}/${employeeCallLimit}人。`
  );
}

