function grantTicketReward(ticketType, count, reason, showPopup = true) {
  const amount = Math.max(1, count ?? 1);

  if (isStoryTutorialActive()) {
    return;
  }

  if (ticketType === "premium") {
    setPremiumEmployeeTickets((current) => current + amount);
  } else if (ticketType === "rookie") {
    setRookieEmployeeTickets((current) => current + amount);
  } else {
    setEmployeeTickets((current) => current + amount);
  }

  setHasEmployeeRecruitNotice(true);

  const reward = {
    ticketType,
    count: amount,
    reason,
  };

  if (showPopup) {
    setTicketRewardResult(reward);
  }

  setLog(`${reason}：${getTicketName(ticketType)}を${amount}枚獲得しました。`);
}


function resetLocalStorageForFreshStart() {
  if (typeof window === "undefined") return;
  Object.keys(window.localStorage)
    .filter((key) => key.startsWith("realEstateGame"))
    .forEach((key) => window.localStorage.removeItem(key));
}

function buildInitialAccountData(overrides = {}) {
  return {
    playerRank: 1,
    playerExp: 0,
    employeeVault: [],
    unlockedStoryAkari: false,
    rookieEmployeeTickets: 0,
    employeeTickets: 0,
    premiumEmployeeTickets: 0,
    medals: 0,
    shine: 0,
    releaseCampaignClaimed: false,
    silverSheets: 0,
    goldSheets: 0,
    rainbowSheets: 0,
    specialMissionData: null,
    items: {},
    usedSecretCommands: {},
    [DEV_DEMO_SHEET_GRANT_KEY]: true,
    updatedAt: new Date().toISOString(),
    ...overrides,
  };
}

function resetAllGameDataFromSettings() {
  const ok = window.confirm("完全初期化しますか？\n\n社員・ランク・経験値・チケット・メダル/シャイン・マップ・セーブデータをすべて削除し、インストール直後の状態に戻します。");
  if (!ok) return;

  const finalOk = window.confirm("本当に完全初期化しますか？\nこの操作は元に戻せません。");
  if (!finalOk) return;

  resetLocalStorageForFreshStart();
  writeAccountData(buildInitialAccountData());
  window.location.reload();
}

function resetGameDataKeepingEmployeesFromSettings() {
  const ok = window.confirm("社員だけ残して初期化しますか？\n\n社員名簿の社員だけ残し、ランク・経験値・チケット・メダル/シャイン・マップ・セーブデータを初期化します。");
  if (!ok) return;

  const accountData = readAccountData();
  const employeeVault = mergeEmployeeCollections(accountData.employeeVault ?? []);
  const keepAkariUnlocked = employeeVault.some((employee) => Number(employee?.id) === 122);
  resetLocalStorageForFreshStart();
  writeAccountData(buildInitialAccountData({
    employeeVault,
    unlockedStoryAkari: keepAkariUnlocked,
  }));
  window.location.reload();
}

function persistSecretCommandUsage(nextUsedCommands) {
  const accountData = readAccountData();
  writeAccountData({
    ...accountData,
    usedSecretCommands: nextUsedCommands,
    updatedAt: new Date().toISOString(),
  });
}

function markSecretCommandUsed(commandKey) {
  const nextUsedCommands = { ...usedSecretCommands, [commandKey]: true };
  setUsedSecretCommands(nextUsedCommands);
  persistSecretCommandUsage(nextUsedCommands);
}

function grantSheetReward(sheetType, amount, reason) {
  const safeAmount = Math.max(1, Math.round(Number(amount) || 1));
  const accountData = readAccountData();
  const currentMedals = Math.max(0, Math.round(Number(accountData.medals ?? accountData.medal ?? 0) || 0));
  const currentShine = Math.max(0, Math.round(Number(accountData.shine ?? accountData.shines ?? 0) || 0));
  const isShine = sheetType === "shine" || sheetType === "gold" || sheetType === "rainbow";
  const nextAccountData = {
    ...accountData,
    medals: isShine ? currentMedals : currentMedals + safeAmount,
    shine: isShine ? currentShine + safeAmount : currentShine,
    silverSheets: 0,
    goldSheets: 0,
    rainbowSheets: 0,
    updatedAt: new Date().toISOString(),
  };
  writeAccountData(nextAccountData);
  setHomeAccountRefreshKey((current) => current + 1);
  const label = isShine ? "シャイン" : "メダル";
  const icon = isShine ? "💎" : "🏅";
  setLog(`${reason}：${icon}${label}を${safeAmount}獲得しました。`);
  alert(`${icon}${label}を${safeAmount}獲得しました。`);
}


function handleDeveloperCommand() {
  const command = normalizeCommandText(developerCommandInput);

  if (!command) return;

  if (command === "野口コーポレーション") {
    setIsDemoMode((current) => {
      const next = !current;
      setLog(next ? "デモモードをONにしました。" : "デモモードをOFFにしました。");
      return next;
    });
    setDeveloperCommandInput("");
    return;
  }

  if (["瑞穂", "水穂", "みずほ", "ミズホ"].map(normalizeCommandText).includes(command)) {
    if (usedSecretCommands.mizuho) {
      alert("このコマンドはすでに使用済みです。使用できるのは1回だけです。");
      return;
    }

    markSecretCommandUsed("mizuho");
    grantTicketReward("rookie", 1, "隠しコマンド：瑞穂", true);
    setDeveloperCommandInput("");
    return;
  }

  if (["岐阜", "ぎふ", "ギフ"].map(normalizeCommandText).includes(command)) {
    if (usedSecretCommands.gifu) {
      alert("このコマンドはすでに使用済みです。使用できるのは1回だけです。");
      return;
    }

    markSecretCommandUsed("gifu");
    grantTicketReward("normal", 1, "隠しコマンド：岐阜", true);
    setDeveloperCommandInput("");
    return;
  }

  if (["名古屋", "なごや", "ナゴヤ"].map(normalizeCommandText).includes(command)) {
    if (usedSecretCommands.nagoya) {
      alert("このコマンドはすでに使用済みです。使用できるのは1回だけです。");
      return;
    }

    markSecretCommandUsed("nagoya");
    grantTicketReward("premium", 1, "隠しコマンド：名古屋", true);
    setDeveloperCommandInput("");
    return;
  }

  if (["MEDAL", "ＭＥＤＡＬ", "medal", "メダル"].map(normalizeCommandText).includes(command)) {
    grantSheetReward("medal", 100, "隠しコマンド");
    setDeveloperCommandInput("");
    return;
  }

  if (["SHINE", "ＳＨＩＮＥ", "shine", "シャイン"].map(normalizeCommandText).includes(command)) {
    grantSheetReward("shine", 10, "隠しコマンド");
    setDeveloperCommandInput("");
    return;
  }

  if (command === normalizeCommandText("一億円") || command === normalizeCommandText("1億円") || command === normalizeCommandText("１億円")) {
    if (usedSecretCommands.money100m) {
      alert("このコマンドはすでに使用済みです。使用できるのは1回だけです。");
      return;
    }

    markSecretCommandUsed("money100m");
    setMoney((current) => current + 10000);
    setLog("隠しコマンド：所持金が1億円増えました。");
    setDeveloperCommandInput("");
    return;
  }

  alert("コマンドが違います。");
}

function assignStoredEmployee(employee, officeId) {
  const targetOfficeId = officeId ?? "hq";
  const currentEmployees = employeesRef.current.length > 0 ? employeesRef.current : employees;
  const alreadyAssigned = currentEmployees.some((item) => item.id === employee.id);

  if (alreadyAssigned) {
    alert("この社員はすでに配属されています");
    return;
  }

  const targetOfficeExists = officeTiles.some((officeTile) => (officeTile.officeId ?? "hq") === targetOfficeId);
  if (!targetOfficeExists) {
    alert("配属先の本社・支店が見つかりません。");
    return;
  }

  if (currentEmployees.length >= employeeCallLimit) {
    alert(`社員呼び出し枠が満員です。現在の上限は${employeeCallLimit}人です。先に社員を保管庫へ戻すか、本社Lvを上げてください。`);
    return;
  }

  const officeName = getOfficeName(targetOfficeId);
  const nextEmployees = [
    ...currentEmployees,
    {
      ...employee,
      officeId: targetOfficeId,
    },
  ];

  employeesRef.current = nextEmployees;
  setEmployees(nextEmployees);

  setEmployeeStorage(
    employeeStorage.filter((item) => item.id !== employee.id)
  );

  setLog(`${employee.name}を${officeName}へ呼び出しました。呼び出し枠:${currentEmployees.length + 1}/${employeeCallLimit}人。`);
}

function unassignEmployee(employee) {
  const ok = window.confirm(
    `${employee.name}を配属から外して、社員保管庫へ戻しますか？`
  );

  if (!ok) return;

  setEmployees(
    employees.filter((item) => item.id !== employee.id)
  );

  setEmployeeStorage([
    ...employeeStorage,
    {
      ...employee,
      officeId: null,
    },
  ]);

  setLog(`${employee.name}を社員保管庫へ戻しました。`);
}

function hireEmployee(employee) {
  const alreadyHired = employees.some((item) => item.id === employee.id);

  if (alreadyHired) {
    alert("この社員はすでに雇用しています");
    return;
  }

  const ok = window.confirm(
    `${employee.name}を採用しますか？\n\n` +
      `レアリティ: ${employee.rarity}\n` +
      `営業: ${employee.sales}\n` +
      `建築: ${employee.construction}\n` +
      `管理: ${employee.management}\n` +
      `採用後: 社員保管庫入り\n` +
      `特殊能力: ${getEmployeeSpecialText(employee)}`
  );

  if (!ok) return;

  setEmployeeStorage([
    ...employeeStorage,
    {
      ...employee,
      officeId: null,
    },
  ]);

  setEmployeeCandidates(
    employeeCandidates.filter((candidate) => candidate.id !== employee.id)
  );

  setLog(`${employee.name}を採用しました。社員保管庫に追加しました。必要に応じて社員配置から呼び出してください。`);
}

function dismissEmployee(employee) {
  unassignEmployee(employee);
}

async function startBuildPlacement(buildingKey) {
  const building = BUILDINGS[buildingKey];

  if (!building) {
    alert("建物を選択してください");
    return;
  }

  if (isNagoyaBridgeTutorialActive()) {
    showNagoyaTutorialBlockedMessage("名古屋編準備中は、通常建物の建設はできません。まずは銀行融資、その後に指定された支店建設だけ進めましょう。");
    alert("名古屋編準備中は通常建物の建設はできません。");
    return;
  }

  if (isStoryTutorialActive()) {
    if (tutorialStep !== STORY_TUTORIAL_STEPS.BUILD_APARTMENT) {
      showStoryTutorialBlockedMessage();
      alert("今は建設の前に、表示されている目標を進めましょう。");
      return;
    }

    if (buildingKey !== "house_1f") {
      showStoryTutorialBlockedMessage();
      alert("チュートリアルでは、平屋戸建だけ建築できます。");
      return;
    }
  }

  if (!hqPlaced) {
    alert("先に本社を設置してください");
    return;
  }

  if (buildEntrySource === "tile" && selectedTile && canUseAsBuildTarget(selectedTile, buildingKey)) {
    setPendingBuildKey(null);
    setPendingBranchPlacement(false);
    setSelectedBuildCategory(null);
    setSelectedHousingType(null);
    setActivePanel("home");
    await build(buildingKey, selectedTile);
    return;
  }

  setPendingBuildKey(buildingKey);
  setPendingBranchPlacement(false);
  setBuildEntrySource("menu");
  setSelectedId(null);
  setActivePanel("build");
  setLog(`${building.name}を建設する土地を選択中です。マップ上の緑色の自分の空き土地をクリックしてください。`);
  alert(`${building.name}を建設する土地を選んでください。

建設可能な土地は緑枠で表示されます。
建てたい土地をマップ上でクリックすると建設確認に進みます。`);
}

function startBranchPlacement() {
  if (isStoryTutorialActive()) {
    showStoryTutorialBlockedMessage();
    alert("チュートリアル中は支店開設はできません。まずは表示されている目標を進めましょう。");
    return;
  }

  if (currentGameMode === "story_nagoya_bridge" && nagoyaTutorialStep !== STORY_NAGOYA_TUTORIAL_STEPS.BUILD_BRANCH) {
    showNagoyaTutorialBlockedMessage("支店建設は、銀行融資の流れを終えてから進めます。今は表示されている目標だけ進めましょう。");
    alert("今は支店建設の手順ではありません。");
    return;
  }

  if (!hqPlaced && !isInitialRemoteBranchSetup) {
    alert("先に本社を設置してください");
    return;
  }

  if (currentGameMode !== "story_nagoya_bridge" && !isInitialRemoteBranchSetup && !isBranchUnlockedByHqLevel) {
    alert(`支店建設は本社Lv${HQ_BRANCH_UNLOCK_LEVEL}から解放されます。現在の本社Lvは${headquarterLevel}です。`);
    return;
  }

  if (buildEntrySource === "tile" && selectedTile && canUseAsBranchTarget(selectedTile)) {
    setPendingBranchPlacement(false);
    setPendingBuildKey(null);
    setSelectedBuildCategory(null);
    setSelectedHousingType(null);
    setActivePanel("home");
    placeBranch(selectedTile);
    return;
  }

  setPendingBranchPlacement(true);
  setPendingBuildKey(null);
  setSelectedId(null);
  setSelectedBuildCategory("支店");
  setActivePanel("build");
  setLog("支店を建てる土地を選択中です。マップ上の緑枠の自分の空き土地をクリックしてください。");
  alert("支店を建てる土地を選んでください。\n\n開設可能な土地は緑枠で表示されます。\n建てたい土地をマップ上でクリックすると支店開設確認に進みます。");
}

async function buyLand() {
  if (!hqPlaced && !isInitialRemoteBranchSetup) {
  alert("先に本社を設置してください");
  return;
}
  if (isNagoyaBridgeTutorialActive()) {
    showNagoyaTutorialBlockedMessage("名古屋編準備中は土地購入はできません。銀行融資と指定支店建設の手順だけ進めましょう。");
    alert("名古屋編準備中は土地購入できません。");
    return;
  }
  if (!selectedTile) return;

  const mainTile = getMainTile(selectedTile);
  const targetTile = mainTile || selectedTile;
  const isTutorialPurchaseTarget =
    isStoryTutorialActive() &&
    (tutorialStep === STORY_TUTORIAL_STEPS.BUY_OLD_HOUSE ||
      tutorialStep === STORY_TUTORIAL_STEPS.BUY_APARTMENT_LAND) &&
    isStoryTutorialTargetTile(targetTile);

  if (!isTutorialPurchaseTarget && selectedTile.owner !== OWNER.SALE && mainTile?.owner !== OWNER.SALE) {
    alert("購入できるのは『売り物件』だけです");
    return;
  }

  if (isStoryTutorialActive()) {
    const expectedTag = tutorialStep === STORY_TUTORIAL_STEPS.BUY_OLD_HOUSE
      ? "old_house"
      : tutorialStep === STORY_TUTORIAL_STEPS.BUY_APARTMENT_LAND
        ? "apartment_land"
        : null;

    if (!expectedTag || targetTile.tutorialTag !== expectedTag) {
      showStoryTutorialBlockedMessage();
      alert("今はチュートリアルの目標だけ購入できます。赤く点滅しているマスを選んでください。");
      return;
    }
  }

  const relatedTiles = tiles.filter(
    (tile) => tile.id === targetTile.id || tile.buildingMainId === targetTile.id
  );

  if (isInitialRemoteBranchSetup) {
    const landTotal = relatedTiles.reduce((sum, tile) => sum + tile.landPrice, 0);
    const buildingValue = calculateBuildingValue(targetTile);
    const purchasePrice = landTotal + buildingValue;

    if (purchasePrice > money) {
      alert(`資金不足のため購入できません。\n\n必要額: ${purchasePrice}万円\n現在資金: ${money}万円`);
      return;
    }

    setMoney(money - purchasePrice);
    setTiles(tiles.map((tile) => {
      if (tile.id === targetTile.id || tile.buildingMainId === targetTile.id) {
        return {
          ...tile,
          owner: OWNER.PLAYER,
          purchaseStatus: null,
          purchaseMonthsLeft: 0,
          purchaseEmployeeIds: [],
          purchaseEmployeeNames: [],
        };
      }
      return tile;
    }));
    setSelectedId(targetTile.id);
    setBuildEntrySource("tile");
    setSelectedBuildCategory("支店");
    setSelectedHousingType(null);
    setPendingBuildKey(null);
    setPendingBranchPlacement(false);
    setActivePanel("build");
    setStoryEvent(STORY_KYOTO_EVENTS.OPENING);
    setLog(`${getGameAreaLabel(currentGameMode)}支店用の土地を確保しました。土地代${purchasePrice}万円を支払いました。次は建設メニューから支店を選択してください。`);
    return;
  }

  const hasOutOfRangeTile = relatedTiles.some((tile) => {
    return !isTileInOfficeRange(tile);
  });

  if (hasOutOfRangeTile) {
    alert("本社・支店の行動範囲外のため購入できません");
    return;
  }

  const landTotal = relatedTiles.reduce((sum, tile) => {
    return sum + tile.landPrice;
  }, 0);

  const buildingValue = calculateBuildingValue(targetTile);

  const purchasePrice = landTotal + buildingValue;

  if (targetTile.purchaseStatus === "purchasing") {
    alert("この土地・物件はすでに購入交渉中です");
    return;
  }

  const actionEmployees = await chooseActionEmployees("土地購入", {
    maxCount: 4,
    baseMonths: 2,
    statKey: "sales",
    targetTile,
  });

  if (actionEmployees.length === 0) return;

  const plannedMonths = estimateActionMonths(2, actionEmployees, "sales");
  const finalPurchasePrice = calculateActionCost(purchasePrice, actionEmployees, "sales", "landPurchase", targetTile);

  if (finalPurchasePrice > money) {
    alert(`資金不足のため購入できません。\n\n必要額: ${finalPurchasePrice}万円\n現在資金: ${money}万円`);
    return;
  }

  const ok = window.confirm(
    `購入交渉を開始しますか？\n\n` +
      `標準価格: ${purchasePrice}万円\n` +
      `購入予定価格: ${finalPurchasePrice}万円\n` +
      `標準期間: 2ヶ月\n` +
      `予定期間: 約${plannedMonths}ヶ月\n` +
      `担当: ${actionEmployees.map((employee) => employee.name).join("・")}`
  );

  if (!ok) return;

  setTiles(
    tiles.map((tile) => {
      if (tile.id === targetTile.id) {
        return {
          ...tile,
          purchaseStatus: "purchasing",
          purchaseMonthsLeft: plannedMonths,
          purchaseBaseMonths: 2,
          purchasePlannedMonths: plannedMonths,
          purchaseBasePrice: purchasePrice,
          purchaseFinalPrice: finalPurchasePrice,
          purchaseEmployeeIds: actionEmployees.map((employee) => employee.id),
          purchaseEmployeeNames: actionEmployees.map((employee) => employee.name),
        };
      }

      return tile;
    })
  );

  markEmployeesBusy(actionEmployees.map((employee) => employee.id), plannedMonths, "土地購入");

  setLog(
    `${targetTile.building ? BUILDINGS[targetTile.building].name : "土地"}の購入交渉を開始しました。` +
      `標準2ヶ月 → 予定${plannedMonths}ヶ月 / 標準${purchasePrice}万円 → 予定${finalPurchasePrice}万円 / ` +
      `担当:${actionEmployees.map((employee) => employee.name).join("・")}`
  );

  if (isStoryTutorialActive()) {
    if (targetTile.tutorialTag === "old_house") {
      setStoryEvent(STORY_TUTORIAL_EVENTS.PURCHASE_OLD_HOUSE_STARTED);
    } else if (targetTile.tutorialTag === "apartment_land") {
      setStoryEvent(STORY_TUTORIAL_EVENTS.PURCHASE_APARTMENT_LAND_STARTED);
    }
  }
}
function placeHQ(hqTypeKey) {
  const alreadyHasHQ = tiles.some((tile) => {
    return tile.owner === OWNER.PLAYER && tile.feature === FEATURE.HQ;
  });

  if (alreadyHasHQ) {
    alert("本社はすでに設置済みです。2つ目の本社は設置できません。");
    setHqPlaced(true);
    setActivePanel("home");
    return;
  }

  if (selectedId == null) {
    alert("土地を選択してください");
    return;
  }

  const hqType = HQ_TYPES[hqTypeKey];

  if (!hqType) {
    alert("本社タイプを選択してください");
    return;
  }

  const tile = tiles.find((t) => t.id === selectedId);

  if (!tile) return;

  if (tile.owner !== OWNER.SALE) {
    alert("売り土地のみ本社設置できます");
    return;
  }

  if (!isBuildableTile(tile)) {
    alert("ここには本社を置けません");
    return;
  }

  const totalCost = tile.landPrice + hqType.cost;

  const ok = window.confirm(
    `${hqType.name}を設置しますか？\n\n` +
      `土地代: ${tile.landPrice}万円\n` +
      `本社建設費: ${hqType.cost}万円\n` +
      `合計: ${totalCost}万円`
  );

  if (!ok) return;

  if (money < totalCost) {
    alert(`必要資金${totalCost}万円に対して資金不足です`);
    return;
  }

  const rooms =
    hqTypeKey === "apartment"
      ? Array.from({ length: hqType.rooms }, (_, index) => {
          const tenantKey =
            hqType.allowedTenants[
              randomInt(0, hqType.allowedTenants.length - 1)
            ];

          const tenant = TENANT_TYPES[tenantKey];
          const occupied = Math.random() < 0.5;

          return {
            roomNo: index + 1,
            tenantType: occupied ? tenantKey : null,
            people: occupied
              ? randomInt(tenant.peopleMin, tenant.peopleMax)
              : 0,
            rent: hqType.baseRent,
            contractRent: occupied ? hqType.baseRent : null,
            contractStartMonth: occupied ? month : null,
            lastRentReviewMonth: occupied ? month : null,
            occupied,
            tenantMonths: 0,
          };
        })
      : [];

  const updatedTiles = tiles.map((t) => {
    if (t.id !== selectedId) return t;

    return {
      ...t,
      owner: OWNER.PLAYER,
      feature: FEATURE.HQ,
      officeId: "hq",
      officeName: "本社",
      officeRange: HQ_ACTION_RANGE,
      hqType: hqTypeKey,
      hqName: hqType.name,
      hqCost: hqType.cost,
      building: hqTypeKey === "apartment" ? "hq_apartment" : null,
      buildingMainId: null,
      rooms,
      age: 0,
      condition: 100,
      leaseCycleStartMonth: month,
    };
  });

  setMoney(money - totalCost);
  setTiles(updatedTiles);
  setHqPlaced(true);
  setActionPoints(Math.max(actionPoints, 1));
  setSelectedId(null);
  setActivePanel("home");

  if (currentGameMode === "story_gifu" && !hasShownGifuHqCompleteGuide) {
    setEmployeeTickets((current) => Math.max(current, 1));
    setHasShownGifuHqCompleteGuide(true);
    setStoryEvent(STORY_GIFU_EVENTS.HQ_PLACED);
    setHasEmployeeRecruitNotice(true);
  }

  setLog(
    `${hqType.name}を設置しました。土地代${tile.landPrice}万円、本社建設費${hqType.cost}万円を支払いました。${currentGameMode === "story_gifu" ? " レア社員採用チケットを1枚獲得しました。" : ""}`
  );
}
async function placeBranch(targetTile = selectedTile) {
  if (isStoryTutorialActive()) {
    showStoryTutorialBlockedMessage();
    alert("チュートリアル中は支店開設はできません。まずは表示されている目標を進めましょう。");
    return false;
  }

  if (currentGameMode === "story_nagoya_bridge" && nagoyaTutorialStep !== STORY_NAGOYA_TUTORIAL_STEPS.BUILD_BRANCH) {
    showNagoyaTutorialBlockedMessage("支店建設は、銀行融資の流れを終えてから進めます。今は表示されている目標だけ進めましょう。");
    alert("今は支店建設の手順ではありません。");
    return false;
  }

  if (!hqPlaced && !isInitialRemoteBranchSetup) {
    alert("先に本社を設置してください");
    return false;
  }

  if (currentGameMode !== "story_nagoya_bridge" && !isInitialRemoteBranchSetup && !isBranchUnlockedByHqLevel) {
    alert(`支店建設は本社Lv${HQ_BRANCH_UNLOCK_LEVEL}から解放されます。現在の本社Lvは${headquarterLevel}です。`);
    return false;
  }

  const branchTargetTile = targetTile;

  if (!branchTargetTile) {
    alert("支店を建てる土地を選択してください");
    return false;
  }

  if (officeTiles.some((officeTile) => officeTile.feature === FEATURE.BRANCH && officeTile.branchUnderConstruction)) {
    alert("現在建設中の支店があります。支店完成後に次の支店を開設できます");
    return false;
  }


  if (branchTargetTile.owner !== OWNER.PLAYER) {
    alert("支店は自分の空き土地にのみ建設できます");
    return false;
  }

  if (!isBuildableTile(branchTargetTile)) {
    alert("ここには支店を建てられません");
    return false;
  }

  if (branchTargetTile.building || branchTargetTile.buildingMainId) {
    alert("建物がある土地には支店を建てられません");
    return false;
  }

  const isNagoyaTutorialBranchTarget =
    currentGameMode === "story_nagoya_bridge" &&
    nagoyaTutorialStep === STORY_NAGOYA_TUTORIAL_STEPS.BUILD_BRANCH &&
    branchTargetTile.tutorialTag === "nagoya_branch_land";

  if (!isNagoyaTutorialBranchTarget && !isInitialRemoteBranchSetup && !isTileInOfficeRange(branchTargetTile)) {
    alert("本社・支店の行動範囲外のため支店を開設できません");
    return false;
  }

  if (!isInitialRemoteBranchSetup && money < BRANCH_OFFICE_COST) {
    alert(`支店開設費${BRANCH_OFFICE_COST}万円が足りません`);
    return false;
  }

  const nearestOfficeDistance = officeTiles.reduce((minDistance, officeTile) => {
    return Math.min(
      minDistance,
      getDistance(branchTargetTile.x, branchTargetTile.y, officeTile.x, officeTile.y)
    );
  }, 999);

  if (!isNagoyaTutorialBranchTarget && !isInitialRemoteBranchSetup && nearestOfficeDistance < OFFICE_MIN_DISTANCE) {
    alert("支店は本社・支店の行動範囲内であれば開設できます。近すぎると営業範囲が広がりにくい点に注意してください。");
    return false;
  }

  const nextBranchNumber = branchCount + 1;
  const officeId = `branch_${Date.now()}`;
  const remoteAreaLabel = getGameAreaLabel(currentGameMode);
  const officeName = isInitialRemoteBranchSetup && nextBranchNumber === 1
    ? `${remoteAreaLabel}支店`
    : `支店${nextBranchNumber}`;

  if (isInitialRemoteBranchSetup) {
    setTiles(tiles.map((tile) => {
      if (tile.id !== branchTargetTile.id) return tile;
      return {
        ...tile,
        owner: OWNER.PLAYER,
        feature: FEATURE.BRANCH,
        officeId,
        officeName,
        branchNumber: nextBranchNumber,
        officeRange: BRANCH_ACTION_RANGE,
        branchUnderConstruction: false,
        branchBuildRemaining: 0,
        branchStandardMonths: 0,
        branchActualMonths: 0,
        branchStandardCost: 0,
        branchActualCost: 0,
        branchEmployeeIds: [],
        branchEmployeeNames: [],
      };
    }));

    const employeesToAutoAssign = employeesRef.current.length > 0 ? employeesRef.current : employees;
    const nextEmployeesAfterBranchOpen = employeesToAutoAssign.map((employee) => {
      const currentOfficeId = String(employee?.officeId ?? "");
      const shouldAutoAssignFounder = employee?.founderCarryOver === true && (
        !currentOfficeId ||
        currentOfficeId === "hq" ||
        currentOfficeId === "waiting" ||
        currentOfficeId === "storage" ||
        currentOfficeId === "待機"
      );

      if (!shouldAutoAssignFounder) return employee;

      const assignedEmployee = {
        ...employee,
        officeId,
        busyUntilMonth: null,
        busyActionName: null,
      };

      return normalizeEmployeeGrowthBase({
        ...assignedEmployee,
        currentAssignment: createEmployeeAssignmentFromGame(assignedEmployee, {
          currentGameMode,
          freeMapKey: isFreeModeKey(currentGameMode) ? normalizeFreeModeKey(currentGameMode) : null,
          areaLabel: remoteAreaLabel,
          activeSaveSlot,
        }),
      });
    });
    employeesRef.current = nextEmployeesAfterBranchOpen;
    setEmployees(nextEmployeesAfterBranchOpen);

    setHqPlaced(true);
    setPendingBranchPlacement(false);
    setPendingBuildKey(null);
    setSelectedBuildCategory(null);
    setSelectedHousingType(null);
    setSelectedId(branchTargetTile.id);
    setActivePanel("home");
    setActionPoints((current) => Math.max(current, 1));
    setStoryEvent(STORY_KYOTO_EVENTS.OPENING);
    setLog(`${officeName}を開設しました。最初の支店は開始準備として即時完成しました。ここから${getGameAreaLabel(currentGameMode)}を開始します。`);
    return true;
  }

  const actionEmployees = await chooseActionEmployees("支店開設", {
    maxCount: 4,
    baseMonths: BRANCH_OFFICE_BASE_MONTHS,
    statKey: "construction",
    targetTile: branchTargetTile,
  });

  if (actionEmployees.length === 0) return false;

  const branchBuildMonths = isNagoyaTutorialBranchTarget ? 3 : estimateActionMonths(BRANCH_OFFICE_BASE_MONTHS, actionEmployees, "construction");
  const actualBranchCost = calculateActionCost(BRANCH_OFFICE_COST, actionEmployees, "construction", "branch", branchTargetTile);

  const ok = window.confirm(
    `${officeName}を開設しますか？\n\n` +
      `標準建築費: ${BRANCH_OFFICE_COST}万円\n` +
      `予定建築費: ${actualBranchCost}万円\n` +
      `営業範囲: ${BRANCH_ACTION_RANGE}マス\n` +
      `担当: ${actionEmployees.map((employee) => employee.name).join("・")}\n` +
      `標準工期: ${BRANCH_OFFICE_BASE_MONTHS}ヶ月\n` +
      `予定工期: 約${branchBuildMonths}ヶ月`
  );

  if (!ok) return false;

  if (money < actualBranchCost) {
    alert(`支店予定建築費${actualBranchCost}万円が足りません`);
    return false;
  }

  setMoney(money - actualBranchCost);

  setTiles(
    tiles.map((tile) => {
      if (tile.id !== branchTargetTile.id) return tile;

      return {
        ...tile,
        owner: OWNER.PLAYER,
        feature: FEATURE.BRANCH,
        officeId,
        officeName,
        branchNumber: nextBranchNumber,
        officeRange: 0,
        branchUnderConstruction: true,
        branchBuildRemaining: branchBuildMonths,
        branchStandardMonths: BRANCH_OFFICE_BASE_MONTHS,
        branchActualMonths: branchBuildMonths,
        branchStandardCost: BRANCH_OFFICE_COST,
        branchActualCost: actualBranchCost,
        branchEmployeeIds: actionEmployees.map((employee) => employee.id),
        branchEmployeeNames: actionEmployees.map((employee) => employee.name),
      };
    })
  );

  setPendingBranchPlacement(false);
  setSelectedId(null);
  markEmployeesBusy(actionEmployees.map((employee) => employee.id), branchBuildMonths, "支店開設");

  setLog(`${officeName}の建設を開始しました。標準${BRANCH_OFFICE_BASE_MONTHS}ヶ月 → 予定${branchBuildMonths}ヶ月 / 標準${BRANCH_OFFICE_COST}万円 → 予定${actualBranchCost}万円 / 担当:${actionEmployees.map((employee) => employee.name).join("・")}`);
  return true;
}

