useEffect(() => {
  if (currentGameMode !== "story_nagoya_bridge" || !nagoyaTutorialStep) return;

  const hasPendingConsultation = pendingLoanConsultations.length > 0;
  const hasConsultationReport = loanConsultationReports.length > 0;
  const hasPendingApplication = pendingLoanApplications.length > 0;
  const hasNagoyaTutorialExecutedLoan = loans.some(
    (loan) => loan.storyNagoyaBridgeLoan === true && (loan.remaining ?? 0) > 0
  );
  const hasBranchUnderConstruction = tiles.some((tile) => tile.feature === FEATURE.BRANCH && tile.branchUnderConstruction);
  const activeBranchOfficeIds = tiles
    .filter((tile) => tile.feature === FEATURE.BRANCH && !tile.branchUnderConstruction && (tile.officeRange ?? 0) > 0)
    .map((tile) => tile.officeId)
    .filter(Boolean);
  const hasActiveBranch = activeBranchOfficeIds.length > 0;
  const hasEmployeeAssignedToActiveBranch = employees.some((employee) => activeBranchOfficeIds.includes(employee.officeId));

  if (nagoyaTutorialStep === STORY_NAGOYA_TUTORIAL_STEPS.LOAN_CONSULT && hasPendingConsultation) {
    setNagoyaTutorialStep(STORY_NAGOYA_TUTORIAL_STEPS.WAIT_LOAN_CONSULT);
    setStoryEvent(STORY_NAGOYA_EVENTS.LOAN_CONSULT_STARTED);
    setLog("融資相談を開始しました。翌月へ進めて相談結果を待ちましょう。");
    return;
  }

  if (nagoyaTutorialStep === STORY_NAGOYA_TUTORIAL_STEPS.WAIT_LOAN_CONSULT && hasConsultationReport) {
    setNagoyaTutorialStep(STORY_NAGOYA_TUTORIAL_STEPS.LOAN_APPLICATION);
    setStoryEvent(STORY_NAGOYA_EVENTS.LOAN_REPORT_READY);
    setActivePanel("bank");
    setLog("融資相談結果が届きました。次は融資申請を行いましょう。");
    return;
  }

  if (nagoyaTutorialStep === STORY_NAGOYA_TUTORIAL_STEPS.LOAN_APPLICATION && hasPendingApplication) {
    setNagoyaTutorialStep(STORY_NAGOYA_TUTORIAL_STEPS.WAIT_LOAN_APPLICATION);
    setStoryEvent(STORY_NAGOYA_EVENTS.LOAN_APPLICATION_STARTED);
    setLog("融資申請を開始しました。翌月へ進めて審査結果を待ちましょう。");
    return;
  }

  if (
    nagoyaTutorialStep === STORY_NAGOYA_TUTORIAL_STEPS.WAIT_LOAN_APPLICATION &&
    !hasPendingApplication &&
    hasNagoyaTutorialExecutedLoan
  ) {
    setNagoyaTutorialStep(STORY_NAGOYA_TUTORIAL_STEPS.BUILD_BRANCH);
    setStoryEvent(STORY_NAGOYA_EVENTS.LOAN_APPROVED);
    setActivePanel("land");
    setLog("融資が実行されました。次は支店建設です。自社の空き地を用意して支店を建てましょう。");
    return;
  }

  if (nagoyaTutorialStep === STORY_NAGOYA_TUTORIAL_STEPS.BUILD_BRANCH && hasBranchUnderConstruction) {
    setNagoyaTutorialStep(STORY_NAGOYA_TUTORIAL_STEPS.WAIT_BRANCH);
    setStoryEvent(STORY_NAGOYA_EVENTS.BRANCH_STARTED);
    setLog("支店建設を開始しました。翌月へ進めて完成を待ちましょう。");
    return;
  }

  if (nagoyaTutorialStep === STORY_NAGOYA_TUTORIAL_STEPS.WAIT_BRANCH && hasActiveBranch) {
    setNagoyaTutorialStep(STORY_NAGOYA_TUTORIAL_STEPS.ASSIGN_BRANCH_EMPLOYEE);
    setStoryEvent(STORY_NAGOYA_EVENTS.BRANCH_COMPLETE);
    setActivePanel("employee");
    setLog("支店が完成しました。社員が足りない場合は、下部メニューの『社員』→『社員採用』で採用し、その後『社員配属』で支店へ配属しましょう。");
    return;
  }

  if (nagoyaTutorialStep === STORY_NAGOYA_TUTORIAL_STEPS.ASSIGN_BRANCH_EMPLOYEE && hasEmployeeAssignedToActiveBranch) {
    setNagoyaTutorialStep(STORY_NAGOYA_TUTORIAL_STEPS.COMPLETE);
    setStoryEvent(STORY_NAGOYA_EVENTS.BRANCH_EMPLOYEE_ASSIGNED);
    setStorySequence(null);
    setStorySequenceIndex(0);
    setActivePanel("home");
    setLog("支店への社員配属が完了しました。名古屋編へ進む準備が整いました。");
  }
}, [currentGameMode, nagoyaTutorialStep, pendingLoanConsultations, loanConsultationReports, pendingLoanApplications, loans, tiles, employees]);

function getCurrentAkariGuide() {
  if (currentGameMode === "story" && tutorialStep) {
    return {
      portrait: "normal",
      title: "1-1章 創業チュートリアル",
      goal: getStoryTutorialGoalText(tutorialStep),
      text: getStoryTutorialAkariAdviceText(tutorialStep),
      nextMonthGuide: shouldShowStoryTutorialNextMonthGuide(),
    };
  }

  if (currentGameMode === "story_nagoya_bridge" && nagoyaTutorialStep) {
    return {
      portrait: "serious",
      title: "2-2章 名古屋編：進出準備",
      goal: getStoryNagoyaGoalText(nagoyaTutorialStep),
      text: getStoryNagoyaAdviceText(nagoyaTutorialStep),
      nextMonthGuide: nagoyaTutorialStep === STORY_NAGOYA_TUTORIAL_STEPS.WAIT_LOAN_CONSULT ||
        nagoyaTutorialStep === STORY_NAGOYA_TUTORIAL_STEPS.WAIT_LOAN_APPLICATION ||
        nagoyaTutorialStep === STORY_NAGOYA_TUTORIAL_STEPS.WAIT_BRANCH,
    };
  }

  if (currentGameMode === "story_nagoya") {
    return {
      portrait: "serious",
      title: "2-2章 名古屋編",
      goal: `実質月利益${NAGOYA_CLEAR_MONTHLY_PROFIT.toLocaleString()}万円以上を目指しましょう。`,
      text: "名古屋編では、支店を使って活動範囲を広げます。社員画面で社員を本社・支店へ配属変更できるので、支店にも担当社員を置いてから購入・建設・修繕を進めましょう。",
      nextMonthGuide: false,
    };
  }

  if (isRemoteBranchStartMode(currentGameMode) && !hqPlaced) {
    const areaLabel = getGameAreaLabel(currentGameMode);
    return {
      portrait: "serious",
      title: currentGameMode === "story_kyoto" ? "3-1章 京都観光チュートリアル：京都支店設置" : currentGameMode === "story_osaka" ? "4-1章 大阪工業チュートリアル：大阪支店設置" : `${areaLabel}：支店設置`,
      goal: `${areaLabel}で活動する支店を設置しましょう。`,
      text: `${areaLabel}は岐阜本社から離れた地域への支店展開です。まずは好きな売地を購入し、建設メニューから支店を選んで${areaLabel}支店を開設しましょう。最初の支店は即時完成します。`,
      nextMonthGuide: false,
    };
  }

  if (currentGameMode === "story_kyoto") {
    return {
      portrait: "happy",
      title: hasCompletedKyotoTourismTutorial ? "3-2章 京都編" : "3-1章 京都観光チュートリアル",
      goal: getStoryKyotoGoalText(!hasCompletedKyotoTourismTutorial),
      text: getStoryKyotoAdviceText(!hasCompletedKyotoTourismTutorial),
      nextMonthGuide: false,
    };
  }

  if (currentGameMode === "story_osaka") {
    return {
      portrait: hasCompletedOsakaIndustrialTutorial ? "serious" : "happy",
      title: hasCompletedOsakaIndustrialTutorial ? "4-2章 大阪編" : "4-1章 大阪工業チュートリアル",
      goal: getStoryOsakaGoalText(!hasCompletedOsakaIndustrialTutorial),
      text: getStoryOsakaAdviceText(!hasCompletedOsakaIndustrialTutorial),
      nextMonthGuide: false,
    };
  }

  if (currentGameMode === "story_tokyo") {
    return {
      portrait: "serious",
      title: "第5章 東京編",
      goal: getStoryTokyoGoalText(),
      text: getStoryTokyoAdviceText(),
      nextMonthGuide: false,
    };
  }

  if (currentGameMode === "story_gifu" && !hqPlaced) {
    return {
      portrait: "serious",
      title: "1-2章 岐阜編：本社設置",
      goal: "本社を設置する土地を選びましょう。",
      text: "普通の本社は初期費用を抑えられます。アパート付き本社は費用が高い代わりに、最初から賃貸収入を狙えます。どちらを選んでも大丈夫です。",
    };
  }

  const guide = AKARI_PAGE_GUIDES[activePanel] ?? AKARI_PAGE_GUIDES.home;
  const gifuGoalText = currentGameMode === "story_gifu"
    ? `岐阜編目標：建物完成 ${gifuOwnedBuildingCount.toLocaleString()} / ${GIFU_CLEAR_BUILDING_COUNT.toLocaleString()}棟`
    : null;

  return {
    portrait: guide.portrait ?? "normal",
    title: guide.title,
    goal: gifuGoalText,
    text: guide.text,
  };
}

const currentAkariGuide = getCurrentAkariGuide();



const hasSaveData = Boolean(savedGame) || hasAnySaveSlot;
const titleSavedMode = savedGame?.currentGameMode ?? currentGameMode ?? "free";
const titleHasStorySave = Boolean(savedGame) && String(titleSavedMode).startsWith("story");
const titleHasFreeSave = Boolean(savedGame) && isFreeModeKey(titleSavedMode);
function getStoryChapterProgressLevel() {
  // 1: 1-1章 / 2: 岐阜編 / 3: 2-1章 名古屋準備編 / 4: 2-2章 名古屋編 / 5: 3-1章 京都観光チュートリアル / 6: 4-1章 大阪工業チュートリアル / 7: 第5章 東京編 / 8: クリア後
  if (storyProgressFlags.tokyo) return 8;
  if (currentGameMode === "story_tokyo" || storyProgressFlags.osaka) return 7;
  if (currentGameMode === "story_osaka" || storyProgressFlags.kyoto) return 6;
  if (currentGameMode === "story_kyoto" || storyProgressFlags.nagoya || currentGameMode === "story_cleared") return 5;
  if (currentGameMode === "story_nagoya") return 4;
  if (currentGameMode === "story_nagoya_bridge" || storyProgressFlags.gifu) return 3;
  if (currentGameMode === "story_gifu") return 2;
  if (titleAccountData.unlockedStoryAkari || currentGameMode === "story_tutorial") return 1;
  return 1;
}

function continueStoryFromTitle() {
  setTitleModal("storySelect");
}

function openLatestStoryFromTitle() {
  if (titleHasStorySave) {
    openGameFromTitle();
    return;
  }
  startNewGameFromTitle(activeSaveSlot, "story");
}

