    const completed = safeCurrent >= safeTarget;
    const claimed = claimedMissionIds.has(mission.id);

    return {
      ...mission,
      current: safeCurrent,
      target: safeTarget,
      completed,
      claimed,
      progressRate: Math.max(0, Math.min(100, Math.round((safeCurrent / safeTarget) * 100))),
    };
