function getStoryTutorialTargetTagForStep(step = tutorialStep) {
  if (
    step === STORY_TUTORIAL_STEPS.BUY_OLD_HOUSE ||
    step === STORY_TUTORIAL_STEPS.REPAIR_OLD_HOUSE
  ) {
    return "old_house";
  }

  if (
    step === STORY_TUTORIAL_STEPS.BUY_APARTMENT_LAND ||
    step === STORY_TUTORIAL_STEPS.BUILD_APARTMENT
  ) {
    return "apartment_land";
  }

  return null;
}

function isStoryTutorialActive() {
  return currentGameMode === "story" &&
    tutorialStep &&
    tutorialStep !== STORY_TUTORIAL_STEPS.COMPLETE;
}

function shouldShowStoryTutorialNextMonthGuide() {
  if (currentGameMode === "story_nagoya_bridge") {
    return nagoyaTutorialStep === STORY_NAGOYA_TUTORIAL_STEPS.WAIT_LOAN_CONSULT ||
      nagoyaTutorialStep === STORY_NAGOYA_TUTORIAL_STEPS.WAIT_LOAN_APPLICATION ||
      nagoyaTutorialStep === STORY_NAGOYA_TUTORIAL_STEPS.WAIT_BRANCH;
  }

  if (currentGameMode !== "story" || !tutorialStep) return false;

  const oldHouseTile = tiles.find((tile) => tile.tutorialTag === "old_house");
  const apartmentLandTile = tiles.find((tile) => tile.tutorialTag === "apartment_land");

  if (oldHouseTile?.purchaseStatus === "purchasing") return true;
  if (oldHouseTile?.repairStatus === "repairing") return true;
  if (apartmentLandTile?.purchaseStatus === "purchasing") return true;
  if (apartmentLandTile?.buildingStatus === "constructing") return true;

  return false;
}

function getNagoyaTutorialGuideClass(guideTarget) {
  if (currentGameMode !== "story_nagoya_bridge") return "";

  if (guideTarget === "bank-menu" &&
    nagoyaTutorialStep === STORY_NAGOYA_TUTORIAL_STEPS.LOAN_CONSULT &&
    activePanel !== "bank"
  ) {
    return "story-ui-target-guide";
  }

  if (guideTarget === "loan-consult" &&
    nagoyaTutorialStep === STORY_NAGOYA_TUTORIAL_STEPS.LOAN_CONSULT
  ) {
    return "story-ui-target-guide";
  }

  if (guideTarget === "loan-application" &&
    nagoyaTutorialStep === STORY_NAGOYA_TUTORIAL_STEPS.LOAN_APPLICATION
  ) {
    return "story-ui-target-guide";
  }

  if (guideTarget === "next-month" && shouldShowStoryTutorialNextMonthGuide()) {
    return "story-ui-target-guide";
  }

  if (guideTarget === "branch-build" &&
    nagoyaTutorialStep === STORY_NAGOYA_TUTORIAL_STEPS.BUILD_BRANCH
  ) {
    return "story-ui-target-guide";
  }

  if (guideTarget === "employee-menu" &&
    nagoyaTutorialStep === STORY_NAGOYA_TUTORIAL_STEPS.ASSIGN_BRANCH_EMPLOYEE
  ) {
    return "story-ui-target-guide";
  }

  if (guideTarget === "employee-recruit" &&
    nagoyaTutorialStep === STORY_NAGOYA_TUTORIAL_STEPS.ASSIGN_BRANCH_EMPLOYEE &&
    activePanel !== "employeeRecruit"
  ) {
    return "story-ui-target-guide";
  }

  if (guideTarget === "employee-assignment" &&
    nagoyaTutorialStep === STORY_NAGOYA_TUTORIAL_STEPS.ASSIGN_BRANCH_EMPLOYEE &&
    activePanel !== "employee"
  ) {
    return "story-ui-target-guide";
  }

  return "";
}

