      const monthlyExpenses = selectedBuilding ? calculateMonthlyExpenses(selectedMainTile) : 0;
      const monthlyBalance = monthlyRentTotal - monthlyExpenses;
      const isInitialBranchSetupTile = Boolean(isInitialRemoteBranchSetup && selectedMainTile);
      const isSelectedMainTileInOfficeRange = isTileInOfficeRange(selectedMainTile);
